insert into public.seasons (id, title, description, starts_on, ends_on) values
  ('daniel', 'Daniel Track', 'Prophetic milestones from the book of Daniel — image, beasts, little horn, sanctuary, and Michael.', null, null),
  ('revelation', 'Revelation Track', 'Prophetic milestones from Revelation — churches, seals, trumpets, beast system, and the millennium.', null, null)
insert into public.chapters (id, title, description, sort_order, season_id) values
  ('signs', 'Signs of Christ''s Return', 'Discover the warnings and symptoms of a world preparing for the Second Advent.', 0, null),
  ('shaking', 'The Shaking', 'Examine the great sifting process within the church as truth and error collide.', 1, null),
  ('latter-rain', 'The Latter Rain', 'The magnificent outpouring of the Holy Spirit to prepare the harvest for the end.', 2, null),
  ('loud-cry', 'The Loud Cry', 'The final warning warning to the world, swelling into a global shout.', 3, null),
  ('seal-of-god', 'The Seal of God', 'The ultimate sign of allegiance in the final test of worship.', 4, null),
  ('time-of-trouble', 'The Time of Trouble', 'The final severe crisis and trial of faith for God''s faithful remnant.', 5, null),
  ('second-coming', 'The Second Coming', 'The glorious, triumphant return of Jesus Christ in majesty and power.', 6, null),
  ('new-earth', 'Heaven and the New Earth', 'The restoration of all things and the eternal reign of peace and joy.', 7, null),
  ('judgment', 'The Investigative Judgment', 'Understand the pre-Advent heavenly court and the cleansing of the sanctuary before Christ returns.', 8, null),
  ('deceptions', 'Last-Day Deceptions', 'Recognize Satan''s final delusions — spiritualism, strong delusion, and the gathering at Armageddon.', 9, null),
  ('daniel-image', 'Daniel: The Great Image', 'Nebuchadnezzar''s dream of the multi-metal statue and the stone cut without hands.', 10, 'daniel'),
  ('daniel-beasts', 'Daniel: Four Beasts', 'The night vision of four great beasts rising from the sea — successive world powers.', 11, 'daniel'),
  ('daniel-horn', 'Daniel: The Little Horn', 'The blasphemous power that rises among the ten horns and speaks great words against the Most High.', 12, 'daniel'),
  ('daniel-sanctuary', 'Daniel: Sanctuary Cleansed', 'The 2300-day prophecy and the cleansing of the sanctuary in heaven.', 13, 'daniel'),
  ('daniel-stand', 'Daniel: Michael Stands Up', 'The close of the book of Daniel — Michael, the sealed book, and the wise who shine.', 14, 'daniel'),
  ('rev-churches', 'Revelation: Seven Churches', 'Christ''s letters to the seven churches of Asia — counsel for every age of the church.', 15, 'revelation'),
  ('rev-seals', 'Revelation: Seven Seals', 'The Lamb opens the sealed book — conquest, conflict, scarcity, and the cry of the martyrs.', 16, 'revelation'),
  ('rev-trumpets', 'Revelation: Seven Trumpets', 'Trumpet judgments that warn the earth as history moves toward the final crisis.', 17, 'revelation'),
  ('rev-beast', 'Revelation: The Beast System', 'Sea beast, earth beast, and the image that enforces false worship in the final crisis.', 18, 'revelation'),
  ('rev-millennium', 'Revelation: The Millennium', 'The thousand years, the binding of Satan, and the final judgment after the first resurrection.', 19, 'revelation'),
  ('daniel-three', 'Daniel: The Fiery Furnace', 'Faith under Nebuchadnezzar''s decree — three Hebrews and the fourth like the Son of God.', 20, 'daniel'),
  ('daniel-five', 'Daniel: Handwriting on the Wall', 'Belshazzar''s feast, sacred vessels, and the sentence written by the divine hand.', 21, 'daniel'),
  ('daniel-six', 'Daniel: In the Lions'' Den', 'Prayer, envy, and deliverance when the law could not be changed.', 22, 'daniel'),
  ('daniel-nine', 'Daniel: Seventy Weeks', 'Gabriel''s prophecy of Messiah the Prince and the determined vision.', 23, 'daniel'),
  ('daniel-ten', 'Daniel: The Glorious Man', 'Vision by the Hiddekel — conflict in the unseen realm and strengthening for the prophet.', 24, 'daniel'),
  ('exodus-sanctuary', 'Exodus: Earthly Sanctuary', 'The tabernacle pattern shown on the mount — shadow of heavenly things.', 25, null),
  ('leviticus-atonement', 'Leviticus: Day of Atonement', 'Annual cleansing of the sanctuary and the scapegoat bearing sin away.', 26, null),
  ('hebrews-sanctuary', 'Hebrews: Heavenly Ministry', 'Christ our High Priest in the true tabernacle pitched by the Lord.', 27, null),
  ('isaiah-comfort', 'Isaiah: Comfort My People', 'Voices in the wilderness and the glory of the LORD revealed.', 28, null),
  ('isaiah-servant', 'Isaiah: The Suffering Servant', 'Messiah wounded for our transgressions and bruised for our iniquities.', 29, null),
  ('joel-prophecy', 'Joel: The Day of the LORD', 'Locust army, trumpet alarm, and Spirit outpouring before the great day.', 30, null),
  ('zechariah-temple', 'Zechariah: Branch and Builder', 'Joshua the high priest, the Branch, and the flying roll.', 31, null),
  ('malachi-remnant', 'Malachi: Sun of Righteousness', 'Messenger of the covenant, robbing God, and the great and dreadful day.', 32, null),
  ('matthew-parables', 'Matthew: Kingdom Parables', 'Ten virgins, talents, and sheep separated from goats.', 33, null),
  ('luke-watchfulness', 'Luke: Watch and Pray', 'Fig tree lesson and readiness for the Son of man.', 34, null),
  ('acts-restoration', 'Acts: Times of Restitution', 'Pentecost power and Peter''s prophecy of all things restored.', 35, null),
  ('romans-gospel', 'Romans: Righteousness of God', 'Justification by faith and hope of the creation''s deliverance.', 36, null),
  ('first-corinthians-resurrection', '1 Corinthians: Resurrection Hope', 'Last trump, corruptible must put on incorruption.', 37, null),
  ('ephesians-armour', 'Ephesians: Whole Armour', 'Stand against wiles of the devil in the evil day.', 38, null),
  ('thessalonians-coming', 'Thessalonians: Coming of the Lord', 'Comfort concerning those who sleep and the man of sin.', 39, null),
  ('second-peter-day', '2 Peter: Day of the Lord', 'Scoffers, new heavens and earth, and growing in grace.', 40, null),
  ('rev-throne', 'Revelation: Throne in Heaven', 'Four beasts, twenty-four elders, and the sealed book.', 41, 'revelation'),
  ('rev-144000', 'Revelation: The 144,000', 'Sealed servants from every tribe before harm to earth.', 42, 'revelation'),
  ('rev-witnesses', 'Revelation: Two Witnesses', 'Olive trees and candlesticks prophesying in sackcloth.', 43, 'revelation'),
  ('rev-woman-dragon', 'Revelation: Woman and Dragon', 'War in heaven, wilderness nurture, and flood from the serpent.', 44, 'revelation'),
  ('rev-harvest', 'Revelation: Harvest of Earth', 'Three angels'' messages, sickle, and winepress of wrath.', 45, 'revelation'),
  ('rev-plagues', 'Revelation: Seven Last Plagues', 'Vials of wrath upon those with mark of the beast.', 46, 'revelation'),
  ('rev-harlot', 'Revelation: Mystery Babylon', 'Harlot on scarlet beast and fall of great city.', 47, 'revelation'),
  ('rev-victory', 'Revelation: Marriage and Victory', 'White horse, marriage supper, and lake of fire.', 48, 'revelation'),
  ('rev-new-creation', 'Revelation: New Creation', 'River of life, tree of life, and invitation to come.', 49, 'revelation'),
  ('genesis-beginnings', 'Genesis: Creation and Fall', 'Origins, Sabbath rest, and the promise after the fall — foundation of last-day hope.', 50, null),
  ('exodus-sabbath', 'Exodus: Law and Sabbath', 'Covenant law, the fourth commandment, and a people sealed as God’s own.', 51, null),
  ('isaiah-sabbath', 'Isaiah: True Sabbath Keeping', 'Isaiah 58’s call to delight in the holy day of the Lord.', 52, null),
  ('ezekiel-watchman', 'Ezekiel: Watchman on the Walls', 'Bloodguilt, warning, and the duty to sound the alarm.', 53, null),
  ('daniel-one', 'Daniel: Faithful in Babylon', 'Purpose of heart, diet test, and wisdom from God.', 54, 'daniel'),
  ('habakkuk-vision', 'Habakkuk: Write the Vision', 'Watchtower faith and the just who live by faith.', 55, null),
  ('zephaniah-day', 'Zephaniah: Day of the Lord', 'Seek meekness before the day of the Lord’s anger.', 56, null),
  ('matthew-signs', 'Matthew: Olivet Signs', 'Further signs from Jesus’ discourse on the Mount of Olives.', 57, null),
  ('john-comfort', 'John: Comfort of the Spirit', 'Promise of the Comforter and truth that sanctifies.', 58, null),
  ('acts-witness', 'Acts: Spirit-Powered Witness', 'Power after the Spirit comes; ends of the earth mission.', 59, null),
  ('romans-righteousness', 'Romans: Righteousness by Faith', 'Gospel power, no condemnation, and the law established by faith.', 60, null),
  ('galatians-liberty', 'Galatians: Gospel Liberty', 'Christ living in me; liberty that serves love.', 61, null),
  ('ephesians-unity', 'Ephesians: One Body', 'Unity of the Spirit and the church as Christ’s body.', 62, null),
  ('philippians-mind', 'Philippians: Mind of Christ', 'Humility, exaltation, and pressing toward the mark.', 63, null),
  ('colossians-christ', 'Colossians: Christ Supreme', 'Christ the Creator, the fullness of the Godhead, and hidden life.', 64, null),
  ('thessalonians-hope', 'Thessalonians: Blessed Hope', 'Comfort of the resurrection and the day of the Lord.', 65, null),
  ('timothy-scripture', 'Timothy: Scripture and Charge', 'Inspiration of Scripture and the charge to preach the word.', 66, null),
  ('hebrews-faith', 'Hebrews: Faith of the Fathers', 'Substance of things hoped for; looking unto Jesus.', 67, null),
  ('james-works', 'James: Faith That Works', 'Doers of the word and pure religion before God.', 68, null),
  ('peter-promise', 'Peter: Precious Promises', 'Partakers of the divine nature and a more sure word.', 69, null),
  ('john-love', 'John: Love and Commandments', 'Love perfected and commandments not grievous.', 70, null),
  ('jude-contend', 'Jude: Contend for the Faith', 'Earnest contention for the once-delivered faith.', 71, null),
  ('rev-letters', 'Revelation: Letters to Churches', 'Further counsel from the seven letters.', 72, 'revelation'),
  ('rev-final', 'Revelation: Final Appeal', 'Last invitations and warnings of the Apocalypse.', 73, 'revelation'),
  ('psalms-refuge', 'Psalms: Refuge and Shepherd', 'Trust, shepherd care, and the word as lamp.', 74, null),
  ('proverbs-wisdom', 'Proverbs: Wisdom’s Call', 'Fear of the Lord and trust that does not lean on self.', 75, null)
