insert into public.words (id, chapter_id, word, clue, expert_clue, verse, scripture, summary, sort_order) values
  ('signs-1', 'signs', 'WARS AND RUMOURS OF WARS', 'Symptom of a troubled world preceding the Second Advent, mentioned in the Olivet discourse.', 'Olivet discourse symptom: nations rise against nations before the end.', 'Matthew 24:6', 'And ye shall hear of wars and rumours of wars: see that ye be not troubled: for all these things must come to pass, but the end is not yet.', 'As the end approaches, international conflicts and political instability serve as reminders that this world is temporary and the return of Christ is near.', 0),
  ('signs-2', 'signs', 'FALSE PROPHETS', 'Deceivers who will arise to show great signs and wonders, attempting to mislead even the elect.', 'Matthew 24 warns these deceivers may show wonders to mislead the elect.', 'Matthew 24:24', 'For there shall arise false Christs, and false prophets, and shall shew great signs and wonders; insomuch that, if it were possible, they shall deceive the very elect.', 'Spiritual deception will reach its climax before the end. The only safeguard against the delusions of the enemy is a deep, personal knowledge of God''s Word.', 1),
  ('signs-3', 'signs', 'PERSECUTION', 'The trial God''s people will face for keeping His commandments and holding the testimony of Jesus.', 'Matthew 13:21 — tribulation or persecution because of the word.', 'Matthew 13:21', 'Yet hath he not root in himself, but dureth for a while: for when tribulation or persecution ariseth because of the word, by and by he is offended.', 'Opposition from the world reveals the true character of our faith and purifies the church, preparing believers to stand in the final conflict.', 2),
  ('signs-4', 'signs', 'PREACHING THE GOSPEL', 'The ultimate gospel task that must be finished in all the world as a witness before the end.', 'Must reach every nation as a witness — then the end arrives.', 'Matthew 24:14', 'And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come.', 'The end will not come until everyone has had a fair opportunity to hear and accept the message of salvation. We are called to cooperate in this great work.', 3),
  ('signs-5', 'signs', 'NATION SHALL RISE AGAINST NATION', 'Jesus lists international conflict among signs of the end in the Olivet discourse.', 'Matthew 24:7 — nation shall rise against nation', 'Matthew 24:7', 'For nation shall rise against nation, and kingdom against kingdom: and there shall be famines, and pestilences, and earthquakes, in divers places. 8 All these are the beginning of sorrows. 9 Then shall they deliver you up to be afflicted, and sha', 'Global unrest is a solemn reminder that history moves toward the promised return of Christ.', 4),
  ('shaking-1', 'shaking', 'SHAKING', 'A testing time among God''s people where the superficial are separated from the faithful.', 'Hebrews 12:27 — only what cannot be shaken will remain.', 'Hebrews 12:27', 'And this word, Yet once more, signifieth the removing of those things that are shaken, as of things that are made, that those things which cannot be shaken may remain.', 'A great sifting occurs as trials and false doctrines test the church. Only those anchored in truth and genuine experience will stand.', 0),
  ('shaking-2', 'shaking', 'STRAIGHT TESTIMONY', 'The direct counsel to the Laodiceans that rouses the church and causes the shaking.', 'Laodicean rebuke: ''As many as I love, I rebuke and chasten.''', 'Revelation 3:19', 'As many as I love, I rebuke and chasten: be zealous therefore, and repent.', 'The True Witness''s testimony is a call to repentance and spiritual revival, dividing those who accept it from those who reject it in self-righteousness.', 1),
  ('shaking-3', 'shaking', 'REJECTION OF TRUTH', 'The choice to compromise or turn away from Bible doctrines, leading to spiritual darkness during sifting.', 'They received not the love of the truth — 2 Thessalonians 2:10.', '2 Thessalonians 2:10', 'And with all deceivableness of unrighteousness in them that perish; because they received not the love of the truth, that they might be saved.', 'Compromise with the world and neglected truth leaves the soul vulnerable to the strong delusions of the last days.', 2),
  ('shaking-4', 'shaking', 'SIFTING', 'The purification process where the chaff of worldly members is blown away from the wheat of God''s church.', 'Amos 9:9 — sifted like corn; not one grain falls to the earth.', 'Amos 9:9', 'For, lo, I will command, and I will sift the house of Israel among all nations, like as corn is sifted in a sieve, yet shall not the least grain fall upon the earth.', 'God permits trials to cleanse His church so that she may be presented pure, united, and ready to receive the power of the Latter Rain.', 3),
  ('shaking-5', 'shaking', 'THINGS WHICH CANNOT BE SHAKEN', 'What remains after God removes what can be shaken.', 'Hebrews 12:27 — things which cannot be shaken may remain', 'Hebrews 12:27', 'Things which cannot be shaken may remain. 28 Wherefore we receiving a kingdom which cannot be moved, let us have grace, whereby we may serve God acceptably with reverence and godly fear: 29 For our God is a consuming fire. 2654 Hebrews 12', 'Only truth rooted in God endures the final shaking of church and world.', 4),
  ('latter-rain-1', 'latter-rain', 'LATTER RAIN', 'The final outpouring of the Holy Spirit to ripen the harvest and empower the loud cry.', 'Joel 2:23 — former rain moderately, latter rain at harvest end.', 'Joel 2:23', 'Be glad then, ye children of Zion, and rejoice in the LORD your God: for he hath given you the former rain moderately, and he will cause to come down for you the rain, the former rain, and the latter rain in the first month.', 'Just as the early rain started the church at Pentecost, the latter rain will finish God''s work on earth with spectacular spiritual power.', 0),
  ('latter-rain-2', 'latter-rain', 'DAY OF PENTECOST', 'The historical outpouring of the Holy Spirit that empowered the early Christian church.', 'Acts 2:1 — when the day of Pentecost was fully come.', 'Acts 2:1', 'And when the day of Pentecost was fully come, they were all with one accord in one place. And suddenly there came a sound from heaven as of a rushing mighty wind, and it filled all the house where they were sitting.', 'Pentecost was the ''early rain'' of the Spirit. The latter rain will be even more abundant, covering the whole earth with the glory of God.', 1),
  ('latter-rain-3', 'latter-rain', 'REFRESHING', 'Times of spiritual reviving and preparation that come from the presence of the Lord.', 'Acts 3:19 — sins blotted out when refreshing comes from His presence.', 'Acts 3:19', 'Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord.', 'Before we can receive the fullness of the Holy Spirit, we must experience personal revival, repentance, and the blotting out of sins.', 2),
  ('latter-rain-4', 'latter-rain', 'HOLY SPIRIT', 'The Divine Agent of the latter rain outpouring, promised by Christ to guide into all truth.', 'Ephesians 1:13 — sealed with that holy Spirit of promise.', 'Ephesians 1:13', 'In whom ye also trusted, after that ye heard the word of truth, the gospel of your salvation: in whom also after that ye believed, ye were sealed with that holy Spirit of promise,', 'We must actively pray for the Holy Spirit daily, preparing our vessels to be filled with the final shower of divine grace.', 3),
  ('latter-rain-5', 'latter-rain', 'YOUR SONS AND YOUR DAUGHTERS SHALL PROPHESY', 'Joel’s promise of Spirit on all flesh before the great day.', 'Joel 2:28 — your sons and your daughters shall prophesy', 'Joel 2:28', 'sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions: 29 And also upon the servants and upon the handmaids in those days will I pour out my spirit. 30 And I will shew wonders in the he', 'The latter rain empowers the final gospel witness as Pentecost empowered the first.', 4),
  ('loud-cry-1', 'loud-cry', 'LOUD CRY', 'The final worldwide warning message that swells from the third angel''s message.', 'Revelation 18:1 — the earth lightened with His glory.', 'Revelation 18:1', 'And after these things I saw another angel come down from heaven, having great power; and the earth was lightened with his glory.', 'An urgent, powerful call that illuminates the entire earth, exposing deception and presenting God''s final invitation of mercy to all mankind.', 0),
  ('loud-cry-2', 'loud-cry', 'THREE ANGELS', 'The special three-fold message of Revelation 14 containing God''s final warning of judgment and worship.', 'Revelation 14''s threefold final warning of judgment and worship.', 'Revelation 14:6-7', 'And I saw another angel fly in the midst of heaven, having the everlasting gospel to preach unto them that dwell on the earth... Saying with a loud voice, Fear God, and give glory to him; for the hour of his judgment is come...', 'This message calls humanity back to worshipping the Creator, warns against false worship, and identifies the faithful who keep God''s commandments.', 1),
  ('loud-cry-3', 'loud-cry', 'BABYLON IS FALLEN', 'The second angel''s declaration that the corrupt world religious systems have departed from truth.', 'Second angel of Revelation 14 — great city fallen twice over.', 'Revelation 14:8', 'And there followed another angel, saying, Babylon is fallen, is fallen, that great city, because she made all nations drink of the wine of the wrath of her fornication.', 'Babylon represents confused, compromised religious bodies that have united with the state. God warns that her spiritual fall is complete.', 2),
  ('loud-cry-4', 'loud-cry', 'OUT OF HER MY PEOPLE', 'The urgent call of the fourth angel to leave Babylon in order to avoid her plagues.', 'Revelation 18:4 — leave before you share in her sins and plagues.', 'Revelation 18:4', 'And I heard another voice from heaven, saying, Come out of her, my people, that ye be not partakers of her sins, and that ye receive not of her plagues.', 'God still has sincere followers within compromised religious systems. This is His loving, final appeal for them to walk in full Biblical truth.', 3),
  ('loud-cry-5', 'loud-cry', 'EARTH WAS LIGHTENED WITH HIS GLORY', 'Revelation 18 angel fills the world with radiant heavenly light.', 'Revelation 18:1 — the earth was lightened with his glory', 'Revelation 18:1', 'earth was lightened with his glory. 2 And he cried mightily with a strong voice, saying, Babylon the great is fallen, is fallen, and is become the habitation of devils, and the hold of every foul spirit, and a cage of every unclean and h', 'The loud cry is not mere volume but global revelation of God’s character and warning.', 4),
  ('seal-of-god-1', 'seal-of-god', 'SEAL OF GOD', 'God''s sign of authority, ownership, and protection placed upon the foreheads of the faithful.', 'Revelation 7:3 — sealed in the forehead before harm to earth.', 'Revelation 7:3', 'Saying, Hurt not the earth, neither the sea, nor the trees, till we have sealed the servants of our God in their foreheads.', 'The seal of God is a settling into the truth, both intellectually and spiritually, so that believers cannot be moved.', 0),
  ('seal-of-god-2', 'seal-of-god', 'SABBATH', 'The seventh-day memorial of creation which serves as the core test of allegiance and the sign of the Seal.', 'Ezekiel 20:12 — sign between God and His people as Creator.', 'Ezekiel 20:12', 'Moreover also I gave them my sabbaths, to be a sign between me and them, that they might know that I am the LORD that sanctify them.', 'As the commandment identifying God as Creator and Sovereign, the Sabbath is the ultimate test of loyalty in the final crisis.', 1),
  ('seal-of-god-3', 'seal-of-god', 'SUNDAY LAW', 'The legislative decree that enforces false worship, establishing the Mark of the Beast in contrast to God''s Sabbath.', 'Legislated false worship day enforced by civil power.', 'Revelation 13:16', 'And he causeth all, both small and great, rich and poor, free and bond, to receive a mark in their right hand, or in their foreheads.', 'A legislative decree that forces individuals to choose between obeying human laws or the immutable, holy law of God.', 2),
  ('seal-of-god-4', 'seal-of-god', 'MARK OF THE BEAST', 'The sign of allegiance to the beast power, received when one knowingly rejects God''s Sabbath for a human substitute.', 'Revelation 13:17 — required for buying and selling.', 'Revelation 13:17', 'And that no man might buy or sell, save he that had the mark, or the name of the beast, or the number of his name.', 'Receiving the mark represents submission to earthly powers over God. It stands in direct, active opposition to the Seal of God.', 3),
  ('seal-of-god-5', 'seal-of-god', 'SEAL THE LAW AMONG MY DISCIPLES', 'Isaiah links sealing God’s law among those who wait for Him.', 'Isaiah 8:16 — Bind up the testimony, seal the law among my disciples', 'Isaiah 8:16', 'Bind up the testimony, seal the law among my disciples. 17 And I will wait upon the Lord, that hideth his face from the house of Jacob, and I will look for him. 18 Behold, I and the children whom the Lord hath given me are for signs and for w', 'God’s seal involves loyalty to His law written in heart and life.', 4),
  ('time-of-trouble-1', 'time-of-trouble', 'CLOSE OF PROBATION', 'The solemn moment when Christ finishes His intercessory sanctuary ministry and the destiny of all is fixed.', 'Revelation 22:11 — character fixed; no mediator remains.', 'Revelation 22:11', 'He that is unjust, let him be unjust still: and he which is filthy, let him be filthy still: and he that is righteous, let him be righteous still: and he that is holy, let him be holy still.', 'When the intercession of Jesus ends, the door of mercy is closed forever. The righteous remain holy, and the wicked remain wicked.', 0),
  ('time-of-trouble-2', 'time-of-trouble', 'TIME OF TROUBLE', 'A period of unprecedented global crisis and distress that occurs after probation closes.', 'Daniel 12:1 — trouble such as never was since there was a nation.', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation...', 'Without an intercessor, the earth experiences the full weight of human rebellion and plagues, but God preserves His faithful ones.', 1),
  ('time-of-trouble-3', 'time-of-trouble', 'TIME OF JACOBS TROUBLE', 'The intense spiritual wrestling and anguish experienced by the saints as they plead for deliverance.', 'Jeremiah 30:7 — Jacob''s anguish, but saved out of it.', 'Jeremiah 30:7', 'Alas! for that day is great, so that none is like it: it is even the time of Jacob''s trouble, but he shall be saved out of it.', 'Believers will review their lives, deeply repenting of any sin, and holding on to God by faith alone, refusing to let Him go.', 2),
  ('time-of-trouble-4', 'time-of-trouble', 'DEATH DECREE', 'The final earthly decree dictating that those who refuse to worship the image of the beast should be killed.', 'Revelation 13:15 — image speaks; refusers face execution.', 'Revelation 13:15', 'And he had power to give life unto the image of the beast, that the image of the beast should both speak, and cause that as many as would not worship the image of the beast should be killed.', 'A decree will be passed to execute God''s commandment-keeping people. But God will step in to deliver His saints.', 3),
  ('time-of-trouble-5', 'time-of-trouble', 'MICHAEL SHALL STAND UP', 'Daniel’s great prince stands for his people in unprecedented trouble.', 'Daniel 12:1 — Michael stand up, the great prince', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every', 'Deliverance is personal and divine when human mediation is finished.', 4),
  ('second-coming-1', 'second-coming', 'SECOND COMING', 'The glorious, literal, and visible return of Jesus Christ in the clouds of heaven.', 'Titus 2:13 — the blessed hope and glorious appearing.', 'Titus 2:13', 'Looking for that blessed hope, and the glorious appearing of the great God and our Saviour Jesus Christ.', 'The climax of the Christian hope. Jesus returns not in secret, but in supreme majesty, visible to every eye.', 0),
  ('second-coming-2', 'second-coming', 'EASTERN SKY', 'The direction where a small cloud, about half the size of a man''s hand, first appears to the waiting saints.', 'Matthew 24:30 — sign of the Son of man seen in heaven''s clouds.', 'Matthew 24:30', 'And then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.', 'A small, dark cloud in the east is the sign of Christ''s approach. As it draws near, it becomes a great, brilliant cloud of glory.', 1),
  ('second-coming-3', 'second-coming', 'RESURRECTION', 'The miraculous awakening of the dead in Christ at the sound of the trumpet.', '1 Corinthians 15:42 — so also is the resurrection of the dead.', '1 Corinthians 15:42', 'So also is the resurrection of the dead. It is sown in corruption; it is raised in incorruption: It is sown in dishonour; it is raised in glory: it is sown in weakness; it is raised in power:', 'Graves are opened worldwide, and the sleeping saints are raised with immortal bodies, reunited with their loved ones.', 2),
  ('second-coming-4', 'second-coming', 'TRANSLATION', 'The instantaneous change of the living righteous from mortality to immortality, caught up to meet the Lord.', '1 Thessalonians 4:17 — living saints caught up to meet Him in the air.', '1 Thessalonians 4:17', 'Then we which are alive and remain shall be caught up together with them in the clouds, to meet the Lord in the air: and so shall we ever be with the Lord.', 'The living faithful are transformed without seeing death, joining the resurrected saints to meet Jesus in the air.', 3),
  ('second-coming-5', 'second-coming', 'EVERY EYE SHALL SEE HIM', 'John’s description of the public, visible return of Christ.', 'Revelation 1:7 — every eye shall see him', 'Revelation 1:7', 'Behold, he cometh with clouds; and every eye shall see him, and they also which pierced him: and all kindreds of the earth shall wail because of him. Even so, Amen. 8 I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to', 'The Advent is not secret; the whole world will know when the King returns.', 4),
  ('new-earth-1', 'new-earth', 'REMNANT', 'The end-time group of believers who keep the commandments of God and have the testimony of Jesus.', 'Revelation 12:17 — keep commandments and hold testimony of Jesus.', 'Revelation 12:17', 'And the dragon was wroth with the woman, and went to make war with the remnant of her seed, which keep the commandments of God, and have the testimony of Jesus Christ.', 'The final fraction of God''s church, characterized by loyalty to His law and possession of the prophetic gift.', 0),
  ('new-earth-2', 'new-earth', 'NEW EARTH', 'God''s restored, Edenic world recreated from the ashes of sin for the eternal home of the redeemed.', 'Revelation 21:1 — first heaven and earth passed away.', 'Revelation 21:1', 'And I saw a new heaven and a new earth: for the first heaven and the first earth were passed away; and there was no more sea.', 'Sin is permanently erased. The earth is restored to its original beauty, and God dwells personally with His people.', 1),
  ('new-earth-3', 'new-earth', 'NEW JERUSALEM', 'The majestic holy city that descends from God out of heaven to become the capital of the New Earth.', 'Revelation 21:2 — holy city prepared as a bride adorned.', 'Revelation 21:2', 'And I John saw the holy city, new Jerusalem, coming down from God out of heaven, prepared as a bride adorned for her husband.', 'The capital city of the saved, filled with the glory of God, built of gold and precious stones, where Christ and His saints reside.', 2),
  ('new-earth-4', 'new-earth', 'NO MORE DEATH', 'The glorious state of eternity where pain, sorrow, crying, and physical expiry are completely banished.', 'Revelation 21:4 — God wipes every tear; pain and death are gone.', 'Revelation 21:4', 'And God shall wipe away all tears from their eyes; and there shall be no more death, neither sorrow, nor crying, neither shall there be any more pain: for the former things are passed away.', 'The ultimate triumph of Christ''s redemption. Every trace of the curse of sin is wiped away, and eternal joy begins.', 3),
  ('new-earth-5', 'new-earth', 'FORMER THINGS ARE PASSED AWAY', 'God’s promise after tears and death are gone from the new creation.', 'Revelation 21:4 — for the former things are passed away', 'Revelation 21:4', 'the former things are passed away. 5 And he that sat upon the throne said, Behold, I make all things new. And he said unto me, Write: for these words are true and faithful. 6 And he said unto me, It is done. I am Alpha and Omega, the begi', 'Sin’s history ends; the redeemed inherit a world where pain is only a memory.', 4),
  ('judgment-1', 'judgment', 'INVESTIGATIVE JUDGMENT', 'The heavenly tribunal where records are examined before Christ''s return to earth.', 'Daniel 7:9-10 — books opened; the Ancient of days presides.', 'Daniel 7:9-10', 'I beheld till the thrones were cast down, and the Ancient of days did sit... thousand thousands ministered unto him, and ten thousand times ten thousand stood before him: the judgment was set, and the books were opened.', 'Before Christ returns as King, heaven conducts a review of every life. This judgment vindicates God''s character and confirms who is ready for eternity.', 0),
  ('judgment-2', 'judgment', 'PRE ADVENT JUDGMENT', 'Divine review that must finish before the Second Coming, not after it.', '2300-day prophecy of Daniel 8:14 points to this cleansing era.', 'Daniel 8:14', 'And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.', 'The Bible places judgment before the Advent. God''s people are judged while probation still lingers, so the living may be prepared to meet Christ.', 1),
  ('judgment-3', 'judgment', 'BLOT OUT SINS', 'The act of removing confessed transgressions from heavenly records during judgment.', 'Acts 3:19 links repentance with sins being blotted out.', 'Acts 3:19', 'Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord.', 'Through faith in Christ, forgiven sins are erased from the books of heaven. This is the gospel assurance that motivates holy living.', 2),
  ('judgment-4', 'judgment', 'CLEANSING OF SANCTUARY', 'The antitypical Day of Atonement when the heavenly temple is purified from sin''s record.', 'Hebrews 8:1-2 — Christ ministers in the true tabernacle pitched by the Lord.', 'Hebrews 9:23', 'It was therefore necessary that the patterns of things in the heavens should be purified with these; but the heavenly things themselves with better sacrifices than these.', 'Just as the earthly sanctuary was cleansed on the Day of Atonement, Christ now removes sin''s defilement from the heavenly sanctuary through His blood.', 3),
  ('judgment-5', 'judgment', 'BOOKS WERE OPENED', 'Daniel’s court scene before the Ancient of days.', 'Daniel 7:10 — the judgment was set, and the books were opened', 'Daniel 7:10', 'judgment was set, and the books were opened. 11 I beheld then because of the voice of the great words which the horn spake: I beheld even till the beast was slain, and his body destroyed, and given to the burning flame. 12 As concerning t', 'Heaven’s records undergird a fair judgment before the sentence of the ages.', 4),
  ('deceptions-1', 'deceptions', 'STRONG DELUSION', 'God permits believing a lie when truth is rejected — a final test of loyalty.', '2 Thessalonians 2:11 — sent because they received not the love of the truth.', '2 Thessalonians 2:11', 'And for this cause God shall send them strong delusion, that they should believe a lie.', 'When humanity refuses to love truth, God withdraws restraining grace. The result is widespread deception that only Bible students will discern.', 0),
  ('deceptions-2', 'deceptions', 'SPIRITUALISM', 'Satan''s end-time masquerade through spirits and signs imitating the dead and divine.', 'Revelation 16:13-14 — three unclean spirits like frogs from dragon, beast, false prophet.', 'Revelation 16:14', 'For they are the spirits of devils, working miracles, which go forth unto the kings of the earth and of the whole world, to gather them to the battle of that great day of God Almighty.', 'Spiritualism will unite the world through miraculous displays. It is one of Satan''s most successful tools to replace faith in Scripture with experience and emotion.', 1),
  ('deceptions-3', 'deceptions', 'UNCLEAN SPIRITS', 'Demonic agents released to perform signs and unite the world for the final conflict.', 'Revelation 16:13 — frog-like spirits from the satanic trinity.', 'Revelation 16:13', 'And I saw three unclean spirits like frogs come out of the mouth of the dragon, and out of the mouth of the beast, and out of the mouth of the false prophet.', 'These spirits perform wonders that deceive rulers and peoples alike, preparing the world to oppose God and His faithful remnant.', 2),
  ('deceptions-4', 'deceptions', 'ARMAGEDDON', 'The symbolic gathering place for the final worldwide showdown between truth and rebellion.', 'Revelation 16:16 — kings gathered to the place called in Hebrew Armageddon.', 'Revelation 16:16', 'And he gathered them together into a place called in the Hebrew tongue Armageddon.', 'Armageddon is not a literal valley battle alone, but the climactic conflict of the ages where all humanity chooses sides for or against God.', 3),
  ('deceptions-5', 'deceptions', 'LYING WONDERS', 'Paul warns of Satan’s power with deceptive signs after the working of the lawless one.', '2 Thessalonians 2:9 — all power and signs and lying wonders', '2 Thessalonians 2:9', 'power and signs and lying wonders, 10 And with all deceivableness of unrighteousness in them that perish; because they received not the love of the truth, that they might be saved. 11 And for this cause God shall send them strong delusion', 'Miracles alone never prove truth; the Word is the test of every wonder.', 4),
  ('daniel-image-1', 'daniel-image', 'GREAT IMAGE', 'The enormous statue of mixed metals that filled the king''s dream of successive world empires.', 'Daniel 2:31 — a terrible, excellent image stood before the king.', 'Daniel 2:31', 'Thou, O king, sawest, and behold a great image. This great image, whose brightness was excellent, stood before thee; and the form thereof was terrible.', 'God revealed the outline of history through a single dream-image, showing that earthly kingdoms rise and fall under His sovereignty.', 0),
  ('daniel-image-2', 'daniel-image', 'HEAD OF GOLD', 'The top of the image representing Babylon, the first kingdom in the prophetic succession.', 'Daniel 2:38 — ''Thou art this head of gold.''', 'Daniel 2:38', 'And wheresoever the children of men dwell, the beasts of the field and the fowls of the heaven hath he given into thine hand, and hath made thee ruler over them all. Thou art this head of gold.', 'Babylon''s glory is symbolized by gold — yet even the head of gold is temporary before the everlasting kingdom of God.', 1),
  ('daniel-image-3', 'daniel-image', 'HIS FEET PART OF IRON AND PART OF CLAY', 'The divided toes of the image showing a mixed, unstable end-time political order.', 'Daniel 2:41 — feet and toes of iron mixed with miry clay.', 'Daniel 2:41', 'And whereas thou sawest the feet and toes, part of potters'' clay, and part of iron, the kingdom shall be divided; but there shall be in it of the strength of the iron, forasmuch as thou sawest the iron mixed with miry clay.', 'The final phase of earthly power is strong yet brittle — never fully united until Christ returns.', 2),
  ('daniel-image-4', 'daniel-image', 'STONE WAS CUT OUT WITHOUT HANDS', 'The supernatural stone that smashes the image and becomes a mountain filling the whole earth.', 'Daniel 2:34 — stone cut out without hands smote the image.', 'Daniel 2:34', 'Thou sawest till that a stone was cut out without hands, which smote the image upon his feet that were of iron and clay, and brake them to pieces.', 'Christ''s kingdom is not of human origin. It ends all earthly empires and fills the earth with righteousness forever.', 3),
  ('daniel-image-5', 'daniel-image', 'GOD OF HEAVEN SET UP A KINGDOM', 'Daniel interprets the stone kingdom that fills the whole earth.', 'Daniel 2:44 — the God of heaven set up a kingdom', 'Daniel 2:44', 'And in the days of these kings shall the God of heaven set up a kingdom, which shall never be destroyed: and the kingdom shall not be left to other people, but it shall break in pieces and consume all these kingdoms, and it shall stand for ever. 45 Forasmuch as thou sawest that', 'Human empires fall; Christ’s kingdom alone is everlasting.', 4),
  ('daniel-beasts-1', 'daniel-beasts', 'FOUR GREAT BEASTS', 'Four diverse animals that came up from the sea, representing four kings or kingdoms.', 'Daniel 7:3 — four great beasts came up from the sea.', 'Daniel 7:3', 'And four great beasts came up from the sea, diverse one from another.', 'From the turbulent sea of nations rise successive empires — a second line of prophecy paralleling the metallic image.', 0),
  ('daniel-beasts-2', 'daniel-beasts', 'THE FIRST WAS LIKE A LION', 'The first beast of Daniel 7, swift and royal, matching Babylon''s golden head.', 'Daniel 7:4 — first beast like a lion with eagle''s wings.', 'Daniel 7:4', 'The first was like a lion, and had eagle''s wings: I beheld till the wings thereof were plucked, and it was lifted up from the earth, and made stand upon the feet as a man, and a man''s heart was given to it.', 'Wings of speed give way to a humbled, humanized form — Babylon''s pride is checked by the God of heaven.', 1),
  ('daniel-beasts-3', 'daniel-beasts', 'RAISED UP ITSELF ON ONE SIDE', 'Daniel''s second beast — lopsided power devouring much flesh.', 'Daniel 7:5 — bear raised on one side with three ribs.', 'Daniel 7:5', 'And behold another beast, a second, like to a bear, and it raised up itself on one side, and it had three ribs in the mouth of it between the teeth of it: and they said thus unto it, Arise, devour much flesh.', 'Medo-Persia''s lopsided strength and conquests fulfill the second stage of the four-beast vision.', 2),
  ('daniel-beasts-4', 'daniel-beasts', 'FOUR WINGS OF A FOWL', 'Third kingdom beast in Daniel 7 — swift empire with multiple heads.', 'Daniel 7:6 — leopard with four wings and four heads.', 'Daniel 7:6', 'After this I beheld, and lo another, like a leopard, which had upon the back of it four wings of a fowl; the beast had also four heads; and dominion was given to it.', 'Swift as a leopard, Greece under Alexander spreads quickly, then divides into four successor domains.', 3),
  ('daniel-beasts-5', 'daniel-beasts', 'FOUR KINGS WHICH SHALL ARISE', 'Angel’s plain interpretation of the four great beasts from the sea.', 'Daniel 7:17 — These great beasts, which are four, are four kings', 'Daniel 7:17', 'These great beasts, which are four, are four kings, which shall arise out of the earth. 18 But the saints of the most High shall take the kingdom, and possess the kingdom for ever, even for ever and ever. 19 Then I would know the truth of the', 'Prophecy decodes empire after empire until the saints receive the kingdom.', 4),
  ('daniel-horn-1', 'daniel-horn', 'LITTLE HORN', 'A horn that arises among ten, uprooting three, with eyes like a man and a mouth speaking great things.', 'Daniel 7:8 — another little horn with eyes and a mouth.', 'Daniel 7:8', 'I considered the horns, and, behold, there came up among them another little horn, before whom there were three of the first horns plucked up by the roots: and, behold, in this horn were eyes like the eyes of man, and a mouth speaking great things.', 'A religio-political power emerges after imperial Rome, marked by intelligence, speech, and the displacement of rivals.', 0),
  ('daniel-horn-2', 'daniel-horn', 'SPEAK GREAT WORDS', 'The little horn''s blasphemous claims against the Most High.', 'Daniel 7:25 — speaks great words against the most High.', 'Daniel 7:25', 'And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time.', 'Blasphemy, persecution of the saints, and attempts to alter divine times and laws identify this power in history and prophecy.', 1),
  ('daniel-horn-3', 'daniel-horn', 'TIME AND TIMES AND THE DIVIDING OF TIME', 'The prophetic period during which the saints are given into the little horn''s hand.', 'Daniel 7:25 — time, times, and the dividing of time.', 'Daniel 7:25', 'And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time.', 'A fixed prophetic timespan limits oppression; God sets the bounds of the little horn''s dominion.', 2),
  ('daniel-horn-4', 'daniel-horn', 'JUDGMENT WAS SET', 'The heavenly court session when the books were opened before the Ancient of days.', 'Daniel 7:26 — the judgment shall sit; dominion taken away.', 'Daniel 7:10', 'A fiery stream issued and came forth from before him: thousand thousands ministered unto him, and ten thousand times ten thousand stood before him: the judgment was set, and the books were opened.', 'Heaven''s judgment answers blasphemy with final justice; the horn''s dominion ends under the verdict of God.', 3),
  ('daniel-horn-5', 'daniel-horn', 'WEAR OUT THE SAINTS', 'The little horn makes war on the holy ones for a prophetic time.', 'Daniel 7:25 — shall wear out the saints of the most High', 'Daniel 7:25', 'And he shall speak great words against the most High, and shall wear out the saints of the most High, and think to change times and laws: and they shall be given into his hand until a time and times and the dividing of time. 26 But the judgment shall sit, and they shall take away his dominion, to c', 'Persecuting power is limited by heaven’s calendar; saints outlast the horn.', 4),
  ('daniel-sanctuary-1', 'daniel-sanctuary', 'TWO THOUSAND AND THREE HUNDRED DAYS', 'The long prophetic period after which the sanctuary shall be cleansed.', 'Daniel 8:14 — unto two thousand and three hundred days.', 'Daniel 8:14', 'And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.', 'This prophetic span anchors Advent hope in a heavenly Day of Atonement work before the Second Coming.', 0),
  ('daniel-sanctuary-2', 'daniel-sanctuary', 'SANCTUARY BE CLEANSED', 'The climactic phrase of Daniel 8:14 announcing purification of the heavenly sanctuary.', 'Daniel 8:14 — then shall the sanctuary be cleansed.', 'Daniel 8:14', 'And he said unto me, Unto two thousand and three hundred days; then shall the sanctuary be cleansed.', 'Cleansing points to Christ''s priestly ministry removing the record of confessed sin in the true tabernacle.', 1),
  ('daniel-sanctuary-3', 'daniel-sanctuary', 'DAILY SACRIFICE', 'The continual ministry cast down by the little horn in Daniel 8''s vision of the ram and goat.', 'Daniel 8:11 — the daily sacrifice was taken away.', 'Daniel 8:11', 'Yea, he magnified himself even to the prince of the host, and by him the daily sacrifice was taken away, and the place of his sanctuary was cast down.', 'Counterfeit systems obscure Christ''s continual priesthood; the sanctuary truth restores the true ministry.', 2),
  ('daniel-sanctuary-4', 'daniel-sanctuary', 'EVENING AND MORNING', 'The prophetic day unit used when the vision of the daily and the transgression is explained.', 'Daniel 8:26 — vision of the evening and the morning is true.', 'Daniel 8:26', 'And the vision of the evening and the morning which was told is true: wherefore shut thou up the vision; for it shall be for many days.', 'Evening-morning language marks prophetic days; the vision reaches far beyond Daniel''s own lifetime.', 3),
  ('daniel-sanctuary-5', 'daniel-sanctuary', 'HOW LONG SHALL BE THE VISION', 'The holy one’s question that introduces the 2300 days.', 'Daniel 8:13 — How long shall be the vision', 'Daniel 8:13', 'How long shall be the vision concerning the daily sacrifice, and the transgression of desolation, to give both the sanctuary and the host to be trodden under foot? 14 And he said unto me, Unto two thousand and three hundred days; then shall', 'Longest prophetic timeline anchors hope in the cleansing of the sanctuary.', 4),
  ('daniel-stand-1', 'daniel-stand', 'MICHAEL STAND UP', 'The great prince who stands for God''s people at the time of unprecedented trouble.', 'Daniel 12:1 — Michael shall stand up, the great prince.', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every one that shall be found written in the book.', 'When Michael stands, deliverance comes for those written in the book — after the final crisis of earth''s history.', 0),
  ('daniel-stand-2', 'daniel-stand', 'WRITTEN IN THE BOOK', 'The record that identifies who will be delivered when Michael stands up.', 'Daniel 12:1 — delivered, every one found written in the book.', 'Daniel 12:1', 'And at that time shall Michael stand up, the great prince which standeth for the children of thy people: and there shall be a time of trouble, such as never was since there was a nation even to that same time: and at that time thy people shall be delivered, every one that shall be found written in the book.', 'Salvation is personal and recorded. Only those found written in the book share Michael''s deliverance.', 1),
  ('daniel-stand-3', 'daniel-stand', 'MANY SHALL RUN TO AND FRO', 'The end-time increase of knowledge and earnest searching of prophecy.', 'Daniel 12:4 — many shall run to and fro; knowledge increased.', 'Daniel 12:4', 'But thou, O Daniel, shut up the words, and seal the book, even to the time of the end: many shall run to and fro, and knowledge shall be increased.', 'As the end nears, sealed prophecy opens and diligent study multiplies understanding among the faithful.', 2),
  ('daniel-stand-4', 'daniel-stand', 'WISE SHALL SHINE', 'Those who turn many to righteousness, shining as the brightness of the firmament.', 'Daniel 12:3 — they that be wise shall shine as the firmament.', 'Daniel 12:3', 'And they that be wise shall shine as the brightness of the firmament; and they that turn many to righteousness as the stars for ever and ever.', 'Wisdom in prophecy leads to soul-winning; the reward is everlasting brightness with the redeemed.', 3),
  ('daniel-stand-5', 'daniel-stand', 'KNOWLEDGE SHALL BE INCREASED', 'End-time running to and fro with increase of knowledge.', 'Daniel 12:4 — knowledge shall be increased', 'Daniel 12:4', 'Knowledge shall be increased. 5 Then I Daniel looked, and, behold, there stood other two, the one on this side of the bank of the river, and the other on that side of the bank of the river. 6 And one said to the man clothed in linen, which wa', 'Sealed prophecy opens as the time of the end arrives.', 4),
  ('rev-churches-1', 'rev-churches', 'SEVEN CHURCHES', 'The congregations in Asia to whom John is commanded to write the Revelation.', 'Revelation 1:11 — write and send unto the seven churches in Asia.', 'Revelation 1:11', 'Saying, I am Alpha and Omega, the first and the last: and, What thou seest, write in a book, and send it unto the seven churches which are in Asia; unto Ephesus, and unto Smyrna, and unto Pergamos, and unto Thyatira, and unto Sardis, and unto Philadelphia, and unto Laodicea.', 'Seven local churches receive living messages that also map the spiritual eras of Christian history.', 0),
  ('rev-churches-2', 'rev-churches', 'FIRST LOVE', 'What Ephesus left behind, and what Christ calls them to remember and do again.', 'Revelation 2:4 — thou hast left thy first love.', 'Revelation 2:4', 'Nevertheless I have somewhat against thee, because thou hast left thy first love.', 'Orthodoxy without love is incomplete. Christ invites the church to return to the affection of its beginning.', 1),
  ('rev-churches-3', 'rev-churches', 'LAODICEA', 'The lukewarm church that says it is rich yet needs gold, raiment, and eyesalve from Christ.', 'Revelation 3:16 — lukewarm, neither cold nor hot.', 'Revelation 3:14', 'And unto the angel of the church of the Laodiceans write; These things saith the Amen, the faithful and true witness, the beginning of the creation of God;', 'End-time self-satisfaction is the danger; Christ''s rebuke is love calling His people to repentance and zeal.', 2),
  ('rev-churches-4', 'rev-churches', 'OPEN DOOR', 'The door Christ sets before Philadelphia that no man can shut.', 'Revelation 3:8 — I have set before thee an open door.', 'Revelation 3:8', 'I know thy works: behold, I have set before thee an open door, and no man can shut it: for thou hast a little strength, and hast kept my word, and hast not denied my name.', 'Mission opportunity and heavenly access open to a faithful remnant who keep His word despite little strength.', 3),
  ('rev-churches-5', 'rev-churches', 'BE ZEALOUS THEREFORE AND REPENT', 'Christ’s counsel to lukewarm Laodicea.', 'Revelation 3:19 — be zealous therefore, and repent', 'Revelation 3:19', 'As many as I love, I rebuke and chasten: be zealous therefore, and repent. 20 Behold, I stand at the door, and knock: if any man hear my voice, and open the door, I will come in to him, and will sup with him, and he with me. 21 To him that overcometh will I grant to sit with me in m', 'Love rebukes; repentance restores the end-time church to usefulness.', 4),
  ('rev-seals-1', 'rev-seals', 'SEALED WITH SEVEN SEALS', 'The scroll in God''s right hand that only the Lamb is worthy to open.', 'Revelation 5:1 — a book sealed with seven seals.', 'Revelation 5:1', 'And I saw in the right hand of him that sat on the throne a book written within and on the backside, sealed with seven seals.', 'Human history''s sealed decrees open only through Christ''s worthiness as the slain yet risen Lamb.', 0),
  ('rev-seals-2', 'rev-seals', 'WHITE HORSE', 'The first seal''s rider going forth conquering and to conquer.', 'Revelation 6:2 — a white horse; he went forth conquering.', 'Revelation 6:2', 'And I saw, and behold a white horse: and he that sat on him had a bow; and a crown was given unto him: and he went forth conquering, and to conquer.', 'The pure advance of the gospel is pictured as a conquering rider under the first seal.', 1),
  ('rev-seals-3', 'rev-seals', 'UNDER THE ALTAR', 'The fifth-seal cry of the martyrs asking how long until their blood is avenged.', 'Revelation 6:9 — souls under the altar slain for the word.', 'Revelation 6:9', 'And when he had opened the fifth seal, I saw under the altar the souls of them that were slain for the word of God, and for the testimony which they held:', 'Persecuted saints are not forgotten; their appeal rises until the final vindication of God.', 2),
  ('rev-seals-4', 'rev-seals', 'SIXTH SEAL', 'The seal of cosmic signs — earthquake, darkened sun, falling stars — before the great day.', 'Revelation 6:12 — great earthquake; sun black as sackcloth.', 'Revelation 6:12', 'And I beheld when he had opened the sixth seal, and, lo, there was a great earthquake; and the sun became black as sackcloth of hair, and the moon became as blood;', 'Nature itself signals the nearness of judgment, calling the world to prepare for the Lamb''s day.', 3),
  ('rev-seals-5', 'rev-seals', 'HOW LONG O LORD HOLY AND TRUE', 'Cry of the fifth-seal martyrs under the altar.', 'Revelation 6:10 — How long, O Lord, holy and true', 'Revelation 6:10', 'How long, O Lord, holy and true, dost thou not judge and avenge our blood on them that dwell on the earth? 11 And white robes were given unto every one of them; and it was said unto them, that they should rest yet for a little season, until', 'Justice delayed is not justice denied; God answers in His time.', 4),
  ('rev-trumpets-1', 'rev-trumpets', 'SEVEN TRUMPETS', 'The series of angel-blown warnings that follow the opening of the seventh seal''s silence.', 'Revelation 8:6 — seven angels with seven trumpets prepared.', 'Revelation 8:6', 'And the seven angels which had the seven trumpets prepared themselves to sound.', 'Trumpets in Scripture summon, warn, and announce war — here they mark successive judgments on a rebellious world.', 0),
  ('rev-trumpets-2', 'rev-trumpets', 'PRAYERS OF THE SAINTS', 'What the angel offers with incense upon the golden altar before the throne.', 'Revelation 8:3 — incense with the prayers of all saints.', 'Revelation 8:3', 'And another angel came and stood at the altar, having a golden censer; and there was given unto him much incense, that he should offer it with the prayers of all saints upon the golden altar which was before the throne.', 'Before trumpets sound, intercession and prayer rise with incense — mercy still mingles with judgment.', 1),
  ('rev-trumpets-3', 'rev-trumpets', 'WOE WOE WOE', 'The triple cry of the eagle announcing the last three trumpets upon earth''s inhabitants.', 'Revelation 8:13 — Woe, woe, woe, to the inhabiters of the earth.', 'Revelation 8:13', 'And I beheld, and heard an angel flying through the midst of heaven, saying with a loud voice, Woe, woe, woe, to the inhabiters of the earth by reason of the other voices of the trumpet of the three angels, which are yet to sound!', 'The final three trumpets intensify crisis; heaven itself warns that greater trouble still approaches.', 2),
  ('rev-trumpets-4', 'rev-trumpets', 'MYSTERY OF GOD SHOULD BE FINISHED', 'What is completed in the days of the voice of the seventh angel when he begins to sound.', 'Revelation 10:7 — the mystery of God should be finished.', 'Revelation 10:7', 'But in the days of the voice of the seventh angel, when he shall begin to sound, the mystery of God should be finished, as he hath declared to his servants the prophets.', 'The seventh trumpet era closes the prophetic mystery and ushers in the finishing of God''s plan of salvation.', 3),
  ('rev-trumpets-5', 'rev-trumpets', 'SEVEN ANGELS WHICH HAD THE SEVEN TRUMPETS', 'Angels prepared to sound the judgments of the trumpets.', 'Revelation 8:6 — seven angels which had the seven trumpets', 'Revelation 8:6', 'And the seven angels which had the seven trumpets prepared themselves to sound. 7 The first angel sounded, and there followed hail and fire mingled with blood, and they were cast upon the earth: and the third part of trees was burnt up, and all gree', 'Trumpets warn the world while mercy still mingles with judgment.', 4),
  ('rev-beast-1', 'rev-beast', 'BEAST RISE UP OUT OF THE SEA', 'The composite leopard-bear-lion power that rises from the sea with seven heads and ten horns.', 'Revelation 13:1 — a beast rise up out of the sea.', 'Revelation 13:1', 'And I stood upon the sand of the sea, and saw a beast rise up out of the sea, having seven heads and ten horns, and upon his horns ten crowns, and upon his heads the name of blasphemy.', 'A blasphemous world power unites features of prior empires and receives authority for a limited prophetic period.', 0),
  ('rev-beast-2', 'rev-beast', 'ANOTHER BEAST COMING UP OUT OF THE EARTH', 'The second beast with two lamb-like horns that speaks as a dragon.', 'Revelation 13:11 — another beast coming up out of the earth.', 'Revelation 13:11', 'And I beheld another beast coming up out of the earth; and he had two horns like a lamb, and he spake as a dragon.', 'Gentle appearance with dragon speech points to a power that begins with liberty yet ends enforcing tyranny.', 1),
  ('rev-beast-3', 'rev-beast', 'IMAGE OF THE BEAST', 'The structure the earth beast causes to be made, which both speaks and kills dissenters.', 'Revelation 13:15 — image of the beast should both speak.', 'Revelation 13:15', 'And he had power to give life unto the image of the beast, that the image of the beast should both speak, and cause that as many as would not worship the image of the beast should be killed.', 'An image copies the first beast''s principle of enforced religion — the final test of worship for every soul.', 2),
  ('rev-beast-4', 'rev-beast', 'NUMBER OF HIS NAME', 'The number of a man associated with the beast — six hundred threescore and six.', 'Revelation 13:18 — his number is Six hundred threescore and six.', 'Revelation 13:17', 'And that no man might buy or sell, save he that had the mark, or the name of the beast, or the number of his name. Here is wisdom. Let him that hath understanding count the number of the beast: for it is the number of a man; and his number is Six hundred threescore and six.', 'Wisdom and understanding are required to identify the beast; Scripture invites careful, prayerful study — not superstition.', 3),
  ('rev-beast-5', 'rev-beast', 'KEEP THE COMMANDMENTS OF GOD', 'Remnant mark with the faith of Jesus in Revelation 14.', 'Revelation 14:12 — keep the commandments of God, and the faith of Jesus', 'Revelation 14:12', 'Here is the patience of the saints: here are they that keep the commandments of God, and the faith of Jesus. 13 And I heard a voice from heaven saying unto me, Write, Blessed are the dead which die in the Lord from henceforth: Yea, saith the Spirit, that they may rest from their labours; and the', 'Commandments of God and faith of Jesus define those who endure.', 4),
  ('rev-millennium-1', 'rev-millennium', 'THOUSAND YEARS', 'The millennial period during which Satan is bound and the saints reign with Christ.', 'Revelation 20:2 — bound him a thousand years.', 'Revelation 20:2', 'And he laid hold on the dragon, that old serpent, which is the Devil, and Satan, and bound him a thousand years,', 'A fixed thousand-year epoch separates the first resurrection of the just from the final destruction of evil.', 0),
  ('rev-millennium-2', 'rev-millennium', 'FIRST RESURRECTION', 'The blessed rising of those who share in life with Christ at the start of the thousand years.', 'Revelation 20:6 — blessed is he that hath part in the first resurrection.', 'Revelation 20:6', 'Blessed and holy is he that hath part in the first resurrection: on such the second death hath no power, but they shall be priests of God and of Christ, and shall reign with him a thousand years.', 'Participation in the first resurrection means eternal safety from the second death and shared reign with Christ.', 1),
  ('rev-millennium-3', 'rev-millennium', 'SECOND DEATH', 'The final destruction that has no power over those in the first resurrection.', 'Revelation 20:14 — this is the second death.', 'Revelation 20:14', 'And death and hell were cast into the lake of fire. This is the second death.', 'Death itself is destroyed; the second death ends sin permanently for those who refuse the first resurrection''s hope.', 2),
  ('rev-millennium-4', 'rev-millennium', 'BOOK OF LIFE', 'The register opened at the great white throne; those not found written are judged accordingly.', 'Revelation 20:15 — not found written in the book of life.', 'Revelation 20:15', 'And whosoever was not found written in the book of life was cast into the lake of fire.', 'Eternal destiny turns on the book of life — a call to trust Christ now while mercy still invites.', 3),
  ('rev-millennium-5', 'rev-millennium', 'THEY LIVED AND REIGNED WITH CHRIST', 'Those in the first resurrection share His rule for a thousand years.', 'Revelation 20:4 — they lived and reigned with Christ a thousand years', 'Revelation 20:4', 'lived and reigned with Christ a thousand years. 5 But the rest of the dead lived not again until the thousand years were finished. This is the first resurrection. 6 Blessed and holy is he that hath part in the first resurrection: on such', 'The millennium is victory for the redeemed and judgment review with Christ.', 4),
  ('daniel-three-1', 'daniel-three', 'IMAGE OF GOLD', 'Nebuchadnezzar''s idol on the plain of Dura that all were commanded to worship.', 'Daniel 3:1 — image of gold', 'Daniel 3:1', 'Nebuchadnezzar the king made an image of gold, whose height was threescore cubits, and the breadth thereof six cubits: he set it up in the plain of Dura, in the province', 'Earthly power demands worship; God''s people must obey Him rather than human decrees.', 0),
  ('daniel-three-2', 'daniel-three', 'FALL DOWN AND WORSHIP', 'The command at the sound of music when the golden image was dedicated.', 'Daniel 3:5 — fall down and worship', 'Daniel 3:5', 'Down and worship the golden image that Nebuchadnezzar the king hath set up: 6 And whoso falleth not down and worshippeth shall the same hour', 'The test of worship is not private opinion but public allegiance when music sounds and crowds bow.', 1),
  ('daniel-three-3', 'daniel-three', 'SEVEN TIMES MORE THAN IT WAS WONT', 'Nebuchadnezzar''s rage turned the execution fire hotter than usual.', 'Daniel 3:19 — seven times more than it was wont', 'Daniel 3:19', 'Times more than it was wont to be heated. 20 And he commanded the most mighty men that were in his army to bind Shadrach, Meshach, and Abed-nego, and', 'Opposition to truth often intensifies when faithful witnesses refuse to compromise.', 2),
  ('daniel-three-4', 'daniel-three', 'LIKE THE SON OF GOD', 'Nebuchadnezzar saw a fourth figure walking free in the flames with the three Hebrews.', 'Daniel 3:25 — like the Son of God', 'Daniel 3:25', '; and the form of the fourth is like the Son of God. 26 Then Nebuchadnezzar came near to the mouth of the burning fiery furnace, and spake, and said, Shadrach, Meshach, and', 'Christ walks with believers in their fiercest trials, preserving them for His glory.', 3),
  ('daniel-three-5', 'daniel-three', 'NOR WAS AN HAIR OF THEIR HEAD SINGED', 'After the furnace, not a hair was singed nor the smell of fire passed on them.', 'Daniel 3:27 — nor was an hair of their head singed', 'Daniel 3:27', 'Was an hair of their head singed, neither were their coats changed, nor the smell of fire had passed on them. 28 Then Nebuchadnezzar spake, and said, Blessed', 'Complete deliverance demonstrates that faith in God is safer than obedience to tyranny.', 4),
  ('daniel-five-1', 'daniel-five', 'GOLDEN VESSELS', 'Temple articles profaned at Babylon''s drunken feast.', 'Daniel 5:2 — golden vessels', 'Daniel 5:2', 'Then they brought the golden vessels that were taken out of the temple of the house of God which was at Jerusalem; and the king, and his princes, his wives,', 'Desecrating what is holy hastens judgment on those who mock God openly.', 0),
  ('daniel-five-2', 'daniel-five', 'FINGERS OF A MANS HAND', 'The part of the hand that wrote on the palace plaster.', 'Daniel 5:5 — fingers of a man''s hand', 'Daniel 5:5', 'In the same hour came forth fingers of a man''s hand, and wrote over against the candlestick upon the plaister of the wall of the king''s palace: and the king saw the part of', 'God interrupts human revelry with warnings the proud cannot ignore.', 1),
  ('daniel-five-3', 'daniel-five', 'MENE MENE TEKEL UPHARSIN', 'The four words Daniel interpreted before Belshazzar.', 'Daniel 5:25 — MENE, MENE, TEKEL, UPHARSIN', 'Daniel 5:25', 'And this is the writing that was written, MENE, MENE, TEKEL, UPHARSIN. 26 This is the interpretation of the thing: MENE; God hath numbered thy kingdom, and finished it. 27 TEKEL; Thou art weighed', 'Heaven weighs character and measures kingdoms; every soul is numbered before God.', 2),
  ('daniel-five-4', 'daniel-five', 'TEKEL THOU ART WEIGHED IN THE BALANCES', 'Daniel told the king he was found wanting in the balances.', 'Daniel 5:27 — TEKEL; Thou art weighed in the balances', 'Daniel 5:27', 'TEKEL; Thou art weighed in the balances, and art found wanting. 28 PERES; Thy kingdom is divided, and given to the Medes and Persians. 1651 Daniel 5', 'No earthly throne exempts a life from God''s moral evaluation.', 3),
  ('daniel-five-5', 'daniel-five', 'IN THAT NIGHT WAS BELSHAZZAR', 'The king of the Chaldeans was slain when the sentence fell.', 'Daniel 5:30 — In that night was Belshazzar the king', 'Daniel 5:30', 'In that night was Belshazzar the king of the Chaldeans slain. 31 And Darius the Median took the kingdom, being about threescore and two years old. 1652 Daniel', 'Probation closes suddenly for those who persist in defiance after clear warning.', 4),
  ('daniel-six-1', 'daniel-six', 'LAW OF THE MEDES AND PERSIANS', 'A decree that could not be altered once signed by the king.', 'Daniel 6:8 — law of the Medes and Persians', 'Daniel 6:8', 'Of the Medes and Persians, which altereth not. 9 Wherefore king Darius signed the writing and the decree. 10 Now when Daniel knew that the writing', 'Human laws may be rigid, but God''s servants answer first to a higher court.', 0),
  ('daniel-six-2', 'daniel-six', 'THREE TIMES A DAY', 'Daniel''s open window prayer toward Jerusalem.', 'Daniel 6:10 — he kneeled upon his knees three times a day', 'Daniel 6:10', '; and his windows being open in his chamber toward Jerusalem, he kneeled upon his knees three times a day, and prayed, and gave thanks before his God, as he did aforetime. 11 Then these men assembled, and found Daniel praying', 'Faithful prayer habits prepare the soul to stand when persecution comes.', 1),
  ('daniel-six-3', 'daniel-six', 'CAST HIM INTO THE DEN OF LIONS', 'The pit where Daniel was cast for praying to his God.', 'Daniel 6:16 — cast him into the den of lions', 'Daniel 6:16', 'Then the king commanded, and they brought Daniel, and cast him into the den of lions. Now the king spake and said unto Daniel, Thy God whom thou servest continually, he will deliver thee. 17 And a stone was', 'The same place meant for destruction became a testimony of divine protection.', 2),
  ('daniel-six-4', 'daniel-six', 'GOD HATH SENT HIS ANGEL', 'Daniel''s explanation for why the lions did not hurt him.', 'Daniel 6:22 — God hath sent his angel', 'Daniel 6:22', 'My God hath sent his angel, and hath shut the lions mouths, that they have not hurt me: forasmuch as before him innocency was found in me; and also', 'Angels minister to those who serve God with an upright heart before Him.', 3),
  ('daniel-six-5', 'daniel-six', 'HE IS THE LIVING GOD', 'Darius decreed that Daniel''s God is the living God whose kingdom shall not be destroyed.', 'Daniel 6:26 — He is the living God, and stedfast for ever', 'Daniel 6:26', 'Is the living God, and stedfast for ever, and his kingdom that which shall not be destroyed, and his dominion shall be even unto the end. 27 He delivereth and rescueth,', 'Even pagan rulers can confess that earthly thrones fade before the eternal kingdom.', 4),
  ('daniel-nine-1', 'daniel-nine', 'SEVENTY WEEKS ARE DETERMINED', 'Time decreed upon Daniel''s people and holy city in Gabriel''s message.', 'Daniel 9:24 — Seventy weeks are determined', 'Daniel 9:24', 'Seventy weeks are determined upon thy people and upon thy holy city, to finish the transgression, and to make an end of sins, and to make reconciliation', 'God marks out prophetic time for finishing transgression and bringing in everlasting righteousness.', 0),
  ('daniel-nine-2', 'daniel-nine', 'MESSIAH THE PRINCE', 'The Anointed One who appears after sixty-nine weeks in the prophecy.', 'Daniel 9:25 — Messiah the Prince', 'Daniel 9:25', 'Messiah the Prince shall be seven weeks, and threescore and two weeks: the street shall be built again, and the wall, even in troublous times.', 'Christ''s first advent was foretold centuries before He entered Jerusalem.', 1),
  ('daniel-nine-3', 'daniel-nine', 'MESSIAH BE CUT OFF', 'Messiah is cut off in the middle of the seventieth week.', 'Daniel 9:26 — shall Messiah be cut off, but not for himself', 'Daniel 9:26', 'And after threescore and two weeks shall Messiah be cut off, but not for himself: and the people of the prince that shall come shall destroy the city and the sanctuary; and the end thereof shall be with', 'The cross was not accident but the fulfillment of heaven''s appointed timetable.', 2),
  ('daniel-nine-4', 'daniel-nine', 'CONFIRM THE COVENANT WITH MANY', 'Messiah confirms the covenant during the final prophetic week.', 'Daniel 9:27 — confirm the covenant with many for one week', 'Daniel 9:27', 'And he shall confirm the covenant with many for one week: and in the midst of the week he shall cause the sacrifice and the oblation to cease, and for the overspreading of abomina1660', 'Christ''s ministry and sacrifice ratified the new covenant with humanity.', 3),
  ('daniel-nine-5', 'daniel-nine', 'ABOMINATION THAT MAKETH DESOLATE', 'Daniel links desolating abominations to the close of the seventy-weeks prophecy.', 'Daniel 9:27 — abomination that maketh desolate', 'Daniel 9:27', 'Abomination that maketh desolate. 1665 Daniel 11', 'False worship desolates what God consecrates — a warning repeated in later prophecy.', 4),
  ('daniel-ten-1', 'daniel-ten', 'CLOTHED IN LINEN', 'A glorious figure girded with gold of Uphaz above the river.', 'Daniel 10:5 — clothed in linen', 'Daniel 10:5', '; 5 Then I lifted up mine eyes, and looked, and behold a certain man clothed in linen, whose loins were girded with fine gold of Uphaz: 6 His body also was like the beryl, and his face as the appearance of', 'Heaven sends visible assurance that spiritual battles are fought under divine leadership.', 0),
  ('daniel-ten-2', 'daniel-ten', 'HIS BODY ALSO WAS LIKE THE BERYL', 'Part of the description of the man by the river Hiddekel.', 'Daniel 10:6 — His body also was like the beryl', 'Daniel 10:6', 'His body also was like the beryl, and his face as the appearance of lightning, and his eyes as lamps of fire, and his arms and his feet like in colour to', 'Prophetic visions reveal the majesty of beings who serve the throne of God.', 1),
  ('daniel-ten-3', 'daniel-ten', 'PRINCE OF THE KINGDOM OF PERSIA', 'A spiritual power that withstood the angel twenty-one days.', 'Daniel 10:13 — prince of the kingdom of Persia', 'Daniel 10:13', 'But the prince of the kingdom of Persia withstood me one and twenty days: but, lo, Michael, one of the chief princes, came to help me; and I remained there with', 'Behind earthly empires stand contending powers in the unseen war over nations.', 2),
  ('daniel-ten-4', 'daniel-ten', 'MICHAEL YOUR PRINCE', 'The chief prince who came to help against the kings of Persia.', 'Daniel 10:21 — Michael your prince', 'Daniel 10:21', 'But I will shew thee that which is noted in the scripture of truth: and there is none that holdeth with me in these things, but Michael your prince.', 'Michael stands for God''s people in heavenly conflict long before Daniel 12.', 3),
  ('daniel-ten-5', 'daniel-ten', 'O MAN GREATLY BELOVED', 'The man touched Daniel and told him to stand upright for the message.', 'Daniel 10:19 — O man greatly beloved, fear not', 'Daniel 10:19', 'O man greatly beloved, fear not: peace be unto thee, be strong, yea, be strong. And when he had spoken unto me, I was strengthened, and said, Let my lord', 'God sustains His servants when revelations of end-time conflict overwhelm human strength.', 4),
  ('exodus-sanctuary-1', 'exodus-sanctuary', 'AFTER THE PATTERN', 'Moses was commanded to build the tabernacle according to the heavenly model.', 'Exodus 25:9 — According to all that I shew thee, after the pattern', 'Exodus 25:9', 'According to all that I shew thee, after the pattern of the tabernacle, and the pattern of all the instruments thereof, even so shall ye make it. 10 And they shall make an ark', 'The earthly sanctuary was a copy of the true tabernacle where Christ ministers.', 0),
  ('exodus-sanctuary-2', 'exodus-sanctuary', 'ARK OF THE TESTIMONY', 'The chest overlaid with gold holding the tables of the law.', 'Exodus 25:16 — ark of the testimony', 'Exodus 25:16', 'And thou shalt put into the ark the testimony which I shall give thee. And thou shalt make a mercy seat of pure gold: two cubits and a half shall be the length thereof, and a cubit and a half the breadth thereof.', 'God''s law at the heart of the sanctuary reveals the standard of His government.', 1),
  ('exodus-sanctuary-3', 'exodus-sanctuary', 'MERCY SEAT OF PURE GOLD', 'The lid where God promised to meet with Moses between the cherubim.', 'Exodus 25:17 — mercy seat of pure gold', 'Exodus 25:17', 'And thou shalt make a mercy seat of pure gold: two cubits and a half shall be the length thereof, and a cubit and a half the breadth thereof. 18 And thou shalt make two', 'Mercy and law meet at the throne where intercession covers repentant sinners.', 2),
  ('exodus-sanctuary-4', 'exodus-sanctuary', 'CANDLESTICK OF PURE GOLD', 'Seven lamps giving light in the holy place.', 'Exodus 25:31 — candlestick of pure gold', 'Exodus 25:31', 'And thou shalt make a candlestick of pure gold: of beaten work shall the candlestick be made: his shaft, and his branches, his bowls, his knops, and his flowers, shall', 'The Spirit illuminates the church as the lampstand lit the first apartment.', 3),
  ('exodus-sanctuary-5', 'exodus-sanctuary', 'VAIL OF BLUE AND PURPLE', 'The curtain separating the holy from the most holy place.', 'Exodus 26:31 — vail of blue, and purple, and scarlet', 'Exodus 26:31', 'And thou shalt make a vail of blue, and purple, and scarlet, and fine twined linen of cunning work: with cherubims shall it be made: 32 And thou shalt hang it upon four pillars of', 'Access to God''s presence was limited until Christ''s flesh was torn for us.', 4),
  ('leviticus-atonement-1', 'leviticus-atonement', 'DAY OF ATONEMENT', 'The tenth day of the seventh month when the high priest made reconciliation.', 'Leviticus 16:29 — day of atonement', 'Leviticus 16:29', 'And this shall be a statute for ever unto you: that in the seventh month, on the tenth day of the month, ye shall afflict your souls, and do no work at all, whether it be one of your own country, or a stranger that sojourneth among you: For on that day shall the priest make an atonement for you, to cleanse you.', 'Typical services pointed forward to Christ''s final work removing sin from the record.', 0),
  ('leviticus-atonement-2', 'leviticus-atonement', 'ONE LOT FOR THE LORD', 'Lots cast — one for the LORD and one for Azazel.', 'Leviticus 16:8 — one lot for the LORD, and the other lot for the scapegoat', 'Leviticus 16:8', 'And Aaron shall cast lots upon the two goats; one lot for the Lord, and the other lot for the scapegoat. 9 And Aaron shall bring the goat upon which the Lord''S lot fell, and offer him for a sin offering. 10 But the goat, on which', 'Sin is both atoned and removed — justice satisfied and guilt borne away.', 1),
  ('leviticus-atonement-3', 'leviticus-atonement', 'WITHIN THE VAIL', 'The high priest entered the most holy only on this day with blood.', 'Leviticus 16:15 — within the vail', 'Leviticus 16:15', 'Within the vail the ark of the testimony: and the vail shall divide unto you between the holy place and the most holy. 34 And thou shalt', 'Only blood could open the inner sanctuary — fulfilled in Christ''s heavenly ministry.', 2),
  ('leviticus-atonement-4', 'leviticus-atonement', 'BEAR UPON HIM ALL THEIR INIQUITIES', 'The live goat sent into the wilderness bearing the confessed transgressions.', 'Leviticus 16:22 — bear upon him all their iniquities unto a land not inhabited', 'Leviticus 16:22', 'And the goat shall bear upon him all their iniquities unto a land not inhabited: and he shall let go the goat in the wilderness. 23 And Aaron shall come into the tabernacle of the congregation, and shall', 'Satan ultimately bears the final responsibility for sin''s origin and deception.', 3),
  ('leviticus-atonement-5', 'leviticus-atonement', 'AFFLICT YOUR SOULS', 'Israel was to humble themselves on the day of atonement.', 'Leviticus 16:31 — afflict your souls', 'Leviticus 16:31', 'Afflict your souls, and do no work at all, whether it be one of your own country, or a stranger that sojourneth among you: 30 For on that day', 'Reconciliation with God requires heartfelt repentance, not mere ritual.', 4),
  ('hebrews-sanctuary-1', 'hebrews-sanctuary', 'HIGH PRIEST FOR EVER', 'Melchisedec order — a priesthood that does not pass to another.', 'Hebrews 6:20 — high priest for ever after the order of Melchisedec', 'Hebrews 6:20', '; 20 Whither the forerunner is for us entered, even Jesus, made an high priest for ever after the order of Melchisedec. Hebrews 6 2642 Hebrews 6', 'Jesus continues interceding because His priesthood never ends.', 0),
  ('hebrews-sanctuary-2', 'hebrews-sanctuary', 'MINISTER OF THE SANCTUARY', 'Christ serves in the true tabernacle which the Lord pitched.', 'Hebrews 8:2 — minister of the sanctuary, and of the true tabernacle', 'Hebrews 8:2', '; 2 A minister of the sanctuary, and of the true tabernacle, which the Lord pitched, and not man. 3 For every high priest is ordained to offer gifts and sacrifices: wherefore it is', 'Heaven''s sanctuary is real — not metaphor but the center of salvation''s administration.', 1),
  ('hebrews-sanctuary-3', 'hebrews-sanctuary', 'MEDIATOR OF A BETTER COVENANT', 'The new covenant with better promises than the old.', 'Hebrews 8:6 — mediator of a better covenant', 'Hebrews 8:6', 'Mediator of a better covenant, which was established upon better promises. 7 For if that first covenant had been faultless, then should no place have', 'God writes His law on the heart under the covenant sealed by Christ''s blood.', 2),
  ('hebrews-sanctuary-4', 'hebrews-sanctuary', 'ONCE IN THE END OF THE WORLD HATH HE APPEARED', 'Christ appeared to put away sin by the sacrifice of Himself.', 'Hebrews 9:26 — once in the end of the world hath he appeared', 'Hebrews 9:26', 'In the end of the world hath he appeared to put away sin by the sacrifice of himself. 27 And as it is appointed unto men once to die, but after this the judgment:', 'One perfect offering ended the need for repeated animal sacrifices.', 3),
  ('hebrews-sanctuary-5', 'hebrews-sanctuary', 'WITHOUT SIN UNTO SALVATION', 'Christ will appear the second time to those who look for Him.', 'Hebrews 9:28 — without sin unto salvation', 'Hebrews 9:28', '; and unto them that look for him shall he appear the second time without sin unto salvation. 2647 Hebrews 9', 'The same Saviour who died once will return for those waiting in faith.', 4),
  ('isaiah-comfort-1', 'isaiah-comfort', 'COMFORT YE COMFORT YE MY PEOPLE', 'Heaven''s command to speak tenderly to Jerusalem.', 'Isaiah 40:1 — Comfort ye, comfort ye my people', 'Isaiah 40:1', 'Chapter 40 Comfort ye, comfort ye my people, saith your God. 2 Speak ye comfortably to Jerusalem, and cry unto her, that her warfare is accomplished, that her iniquity', 'God''s message to the end-time church blends comfort with preparation.', 0),
  ('isaiah-comfort-2', 'isaiah-comfort', 'VOICE OF HIM THAT CRIETH IN THE WILDERNESS', 'Prepare the way of the LORD — make straight a highway.', 'Isaiah 40:3 — voice of one crying in the wilderness', 'Isaiah 40:3', 'The voice of him that crieth in the wilderness, Prepare ye the way of the LORD, make straight in the desert a highway for our God. Every valley shall be exalted, and every mountain and hill shall be made low.', 'John the Baptist and end-time heralds call hearts to level every obstacle to Christ.', 1),
  ('isaiah-comfort-3', 'isaiah-comfort', 'ALL FLESH IS GRASS', 'Human glory fades but the word of our God stands forever.', 'Isaiah 40:6 — All flesh is grass', 'Isaiah 40:6', 'And he said, What shall I cry? All flesh is grass, and all the goodliness thereof is as the flower of the field: 7 The grass withereth, the flower fadeth: because the spirit', 'Prophetic study anchors the soul in what is eternal, not what withers.', 2),
  ('isaiah-comfort-4', 'isaiah-comfort', 'WORD OF OUR GOD SHALL STAND FOR EVER', 'Contrast to fading grass and flower of the field.', 'Isaiah 40:8 — word of our God shall stand for ever', 'Isaiah 40:8', 'The grass withereth, the flower fadeth: but the word of our God shall stand for ever. 9 O Zion, that bringest good tidings, get thee up into the high mountain; O Jerusalem, that bringest good tidings, lift', 'Scripture remains the unchanging foundation when cultures and empires pass.', 3),
  ('isaiah-comfort-5', 'isaiah-comfort', 'HE GIVETH POWER TO THE FAINT', 'They that wait upon the LORD renew their strength.', 'Isaiah 40:29 — He giveth power to the faint', 'Isaiah 40:29', 'He giveth power to the faint; and to them that have no might he increaseth strength. 30 Even the youths shall faint and be weary, and the young men shall', 'End-time endurance comes from waiting on God, not human enthusiasm.', 4),
  ('isaiah-servant-1', 'isaiah-servant', 'HE IS DESPISED AND REJECTED OF MEN', 'The servant had no form nor comeliness that we should desire him.', 'Isaiah 53:3 — He is despised and rejected of men', 'Isaiah 53:3', 'He is despised and rejected of men; a man of sorrows, and acquainted with grief: and we hid as it were our faces from him; he was despised, and we esteemed', 'The world''s rejection of Christ reveals how sin blinds hearts to beauty.', 0),
  ('isaiah-servant-2', 'isaiah-servant', 'WOUNDED FOR OUR TRANSGRESSIONS', 'He was bruised for our iniquities; chastisement brought us peace.', 'Isaiah 53:5 — wounded for our transgressions', 'Isaiah 53:5', 'But he was wounded for our transgressions, he was bruised for our iniquities: the chastisement of our peace was upon him; and with his stripes we are healed. 6 All', 'Substitutionary suffering is the heart of the gospel and prophetic hope.', 1),
  ('isaiah-servant-3', 'isaiah-servant', 'LAID ON HIM THE INIQUITY OF US ALL', 'Isaiah 53 — the LORD caused the guilt of us all to fall on the suffering Servant.', 'Isaiah 53:6 — laid on him the iniquity of us all', 'Isaiah 53:6', '; and the Lord hath laid on him the iniquity of us all. 7 He was oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as', 'Christ bore collective guilt so repentant sinners might go free.', 2),
  ('isaiah-servant-4', 'isaiah-servant', 'OPENED NOT HIS MOUTH', 'As a lamb to slaughter, the servant was silent before shearers.', 'Isaiah 53:7 — opened not his mouth', 'Isaiah 53:7', 'He was oppressed, and he was afflicted, yet he opened not his mouth: he is brought as a lamb to the slaughter, and as a sheep before her shearers is dumb, so he openeth not his mouth. 8 He', 'Messiah''s silence at trial fulfilled prophecy and revealed perfect submission.', 3),
  ('isaiah-servant-5', 'isaiah-servant', 'MADE INTERCESSION FOR THE TRANSGRESSORS', 'He bore sin of many and makes intercession for transgressors.', 'Isaiah 53:12 — made intercession for the transgressors', 'Isaiah 53:12', '; and he bare the sin of many, and made intercession for the transgressors. Isaiah 53 1393 Isaiah 53', 'The same priest who died still pleads for those who come to God through Him.', 4),
  ('joel-prophecy-1', 'joel-prophecy', 'BLOW YE THE TRUMPET IN ZION', 'Alarm sounded in God''s holy mountain before the day of the LORD.', 'Joel 2:1 — Blow ye the trumpet in Zion', 'Joel 2:1', 'Chapter 2 Blow ye the trumpet in Zion, and sound an alarm in my holy mountain: let all the inhabitants of the land tremble: for the day of the Lord cometh, for', 'Heaven calls the church to warn the world while mercy still lingers.', 0),
  ('joel-prophecy-2', 'joel-prophecy', 'DAY OF DARKNESS AND OF GLOOMINESS', 'Joel describes the day of the LORD as terrible and not to be desired.', 'Joel 2:2 — day of darkness and of gloominess', 'Joel 2:2', '; 2 A day of darkness and of gloominess, a day of clouds and of thick darkness, as the morning spread upon the mountains: a great people and a strong; there hath', 'Prophetic language prepares believers for crisis without fostering fear without faith.', 1),
  ('joel-prophecy-3', 'joel-prophecy', 'I WILL POUR OUT MY SPIRIT UPON ALL FLESH', 'Promise of Spirit on all flesh before the great and terrible day.', 'Joel 2:28 — I will pour out my spirit upon all flesh', 'Joel 2:28', 'And it shall come to pass afterward, that I will pour out my spirit upon all flesh; and your sons and your daughters shall prophesy, your old men shall dream dreams, your young men shall see visions: 29 And', 'Pentecost and the latter rain share one promise — universal Spirit empowerment.', 2),
  ('joel-prophecy-4', 'joel-prophecy', 'SUN SHALL BE TURNED INTO DARKNESS', 'Wonders in heaven and earth before the great and terrible day.', 'Joel 2:31 — The sun shall be turned into darkness', 'Joel 2:31', 'The sun shall be turned into darkness, and the moon into blood, before the great and the terrible day of the Lord come. 32 And it shall come to pass, that whosoever', 'Cosmic signs accompany both Pentecost-era fulfillment and final crisis.', 3),
  ('joel-prophecy-5', 'joel-prophecy', 'VALLEY OF DECISION', 'Multitudes gathered where the day of the LORD is near.', 'Joel 3:14 — valley of decision', 'Joel 3:14', 'Multitudes, multitudes in the valley of decision: for the day of the Lord is near in the valley of decision. 15 The sun and the moon shall be darkened, and the stars shall', 'Every soul eventually chooses sides in the great controversy between Christ and Satan.', 4),
  ('zechariah-temple-1', 'zechariah-temple', 'BRAND PLUCKED OUT OF THE FIRE', 'Israel pictured as a burning stick snatched from the flames.', 'Zechariah 3:2 — brand plucked out of the fire', 'Zechariah 3:2', '; even the Lord that hath chosen Jerusalem rebuke thee: is not this a brand plucked out of the fire? 3 Now Joshua was clothed with filthy garments, and stood before the angel. 4 And he answered and spake unto those that stood', 'God preserves a remnant despite their filthy garments and Satan''s accusations.', 0),
  ('zechariah-temple-2', 'zechariah-temple', 'CHANGE OF RAIMENT', 'Joshua stood before the angel with filthy garments removed.', 'Zechariah 3:4 — change of raiment', 'Zechariah 3:4', 'Change of raiment. 5 And I said, Let them set a fair mitre upon his head. So they set a fair mitre upon his head, and clothed him with garments.', 'Justification covers the believer with Christ''s righteousness in heavenly court.', 1),
  ('zechariah-temple-3', 'zechariah-temple', 'BEHOLD THE MAN WHOSE NAME IS THE BRANCH', 'The name of the Branch who shall build the temple of the LORD.', 'Zechariah 6:12 — Behold the man whose name is The BRANCH', 'Zechariah 6:12', '; 12 And speak unto him, saying, Thus speaketh the Lord of hosts, saying, Behold the man whose name is The BRANCH; and he shall grow up out of his place, and he shall build the temple of the Lord: 13 Even he shall build the temple of', 'Christ builds a spiritual temple of living stones from every nation.', 2),
  ('zechariah-temple-4', 'zechariah-temple', 'NOT BY MIGHT NOR BY POWER BUT BY MY SPIRIT', 'Zerubbabel shall finish the work by My Spirit, saith the LORD.', 'Zechariah 4:6 — Not by might, nor by power, but by my spirit', 'Zechariah 4:6', 'Zerubbabel, saying, Not by might, nor by power, but by my spirit, saith the Lord of hosts. 7 Who art thou, O great mountain? before Zerubbabel thou shalt become a plain: and he shall bring', 'Final gospel work succeeds through Spirit power, not human schemes.', 3),
  ('zechariah-temple-5', 'zechariah-temple', 'FLYING ROLL', 'The curse goes forth over the whole earth against thieves and false swearers.', 'Zechariah 5:3 — flying roll', 'Zechariah 5:3', 'Then I turned, and lifted up mine eyes, and looked, and behold a flying roll. 2 And he said unto me, What seest thou? And I answered, I see a flying roll; the length thereof is twenty cubits, and the', 'God''s law still bears witness against sin in every land before judgment falls.', 4),
  ('malachi-remnant-1', 'malachi-remnant', 'MESSENGER OF THE COVENANT', 'The Lord whom ye seek shall suddenly come to His temple.', 'Malachi 3:1 — messenger of the covenant', 'Malachi 3:1', 'Messenger of the covenant, whom ye delight in: behold, he shall come, saith the Lord of hosts. 2 But who may abide the day of his coming? and who', 'John prepared the way; Christ fulfilled the covenant promise at His first advent.', 0),
  ('malachi-remnant-2', 'malachi-remnant', 'LIKE A REFINERS FIRE', 'He shall sit as a refiner and purifier of the sons of Levi.', 'Malachi 3:2 — refiner''s fire, and like fullers'' sope', 'Malachi 3:2', 'Refiner''s fire, and like fullers'' sope: 3 And he shall sit as a refiner and purifier of silver: and he shall purify the sons of Levi, and purge them as gold and', 'Preparation for the end purges character as fire purges metal.', 1),
  ('malachi-remnant-3', 'malachi-remnant', 'WILL A MAN ROB GOD', 'Israel asked wherein they had robbed God — tithes and offerings.', 'Malachi 3:8 — Will a man rob God? Yet ye have robbed me', 'Malachi 3:8', 'But ye said, Wherein shall we return? 8 Will a man rob God? Yet ye have robbed me. But ye say, Wherein have we robbed thee? In tithes and offerings. 9 Ye are cursed with a curse: for ye have robbed me,', 'Stewardship reveals trust in God''s provision during the closing work.', 2),
  ('malachi-remnant-4', 'malachi-remnant', 'BOOK OF REMEMBRANCE WAS WRITTEN BEFORE HIM', 'A book written for those who feared the LORD and thought upon His name.', 'Malachi 3:16 — book of remembrance was written before him', 'Malachi 3:16', 'Of remembrance was written before him for them that feared the Lord, and that thought upon his name. 17 And they shall be mine, saith the Lord of hosts, in that', 'Heaven records faithfulness that earth may forget or ridicule.', 3),
  ('malachi-remnant-5', 'malachi-remnant', 'SUN OF RIGHTEOUSNESS ARISE WITH HEALING IN HIS WINGS', 'Malachi''s closing hope for those who fear God''s name.', 'Malachi 4:2 — Sun of righteousness arise with healing in his wings', 'Malachi 4:2', 'But unto you that fear my name shall the Sun of righteousness arise with healing in his wings; and ye shall go forth, and grow up as calves of the stall. 3 And ye shall tread down the wicked; for they shall be ashes', 'The same day that burns the wicked brings healing to those who serve God.', 4),
  ('matthew-parables-1', 'matthew-parables', 'TEN VIRGINS', 'They went to meet the bridegroom — five wise and five foolish.', 'Matthew 25:1 — ten virgins, which took their lamps', 'Matthew 25:1', 'Then shall the kingdom of heaven be likened unto ten virgins, which took their lamps, and went forth to meet the bridegroom. 2 And five of them were wise, and five were foolish. 3 They that were foolish took', 'Outward profession without inner oil fails when the cry sounds at midnight.', 0),
  ('matthew-parables-2', 'matthew-parables', 'BEHOLD THE BRIDEGROOM COMETH', 'The shout that roused the sleeping virgins to trim their lamps.', 'Matthew 25:6 — at midnight there was a cry made, Behold, the bridegroom com', 'Matthew 25:6', 'And at midnight there was a cry made, Behold, the bridegroom cometh; go ye out to meet him. 7 Then all those virgins arose, and trimmed their lamps. 8 And the foolish said unto the wise, Give', 'Sudden awakening precedes Christ''s return — preparation cannot be borrowed at the last moment.', 1),
  ('matthew-parables-3', 'matthew-parables', 'I WAS AN HUNGRED', 'The King judges nations by treatment of the least of His brethren.', 'Matthew 25:35 — I was an hungred, and ye gave me meat', 'Matthew 25:35', 'I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in: 36 Naked, and ye clothed me: I was sick, and', 'Practical compassion toward God''s people marks those ready for the kingdom.', 2),
  ('matthew-parables-4', 'matthew-parables', 'DEPART FROM ME YE CURSED', 'Those on the left hear sentence into everlasting fire prepared for devil and angels.', 'Matthew 25:41 — Depart from me, ye cursed', 'Matthew 25:41', 'Then shall he say also unto them on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels: 42 For I was an hungred, and ye gave me no meat: I was thirsty,', 'Final separation is real — character fixed in relation to Christ and His people.', 3),
  ('matthew-parables-5', 'matthew-parables', 'ENTER THOU INTO THE JOY', 'The faithful servant invited into the joy of the lord.', 'Matthew 25:21 — Enter thou into the joy of thy lord', 'Matthew 25:21', 'Thou into the joy of thy lord. 22 He also that had received two talents came and said, Lord, thou deliveredst unto me two talents: behold, I have gained', 'Stewardship of gifts now determines participation in eternal joy.', 4),
  ('luke-watchfulness-1', 'luke-watchfulness', 'BEHOLD THE FIG TREE AND ALL THE TREES', 'When leaves appear, summer is near — so know the kingdom is nigh.', 'Luke 21:29 — Behold the fig tree, and all the trees', 'Luke 21:29', 'And he spake to them a parable; Behold the fig tree, and all the trees; 30 When they now shoot forth, ye see and know of your own selves that summer is now nigh at hand. 31 So likewise ye, when', 'Signs in prophecy are meant to inspire watchfulness, not date-setting pride.', 0),
  ('luke-watchfulness-2', 'luke-watchfulness', 'THIS GENERATION SHALL NOT PASS AWAY', 'Christ''s assurance that His prophetic word outlasts heaven and earth.', 'Luke 21:32 — This generation shall not pass away', 'Luke 21:32', 'Verily I say unto you, This generation shall not pass away, till all be fulfilled. 33 Heaven and earth shall pass away: but my words shall not pass away. 34 And take heed to yourselves,', 'Prophetic word is sure even when centuries unfold before fulfillment.', 1),
  ('luke-watchfulness-3', 'luke-watchfulness', 'TAKE HEED TO YOURSELVES LEST AT ANY TIME YOUR HEARTS BE OVERCHARGED', 'Lest hearts be overcharged with surfeiting and cares of this life.', 'Luke 21:34 — Take heed to yourselves, lest at any time your hearts be ove', 'Luke 21:34', 'And take heed to yourselves, lest at any time your hearts be overcharged with surfeiting, and drunkenness, and cares of this life, and so that day come upon you unawares. 35 For as a snare shall', 'Spiritual drowsiness is the danger of the last days as much as open sin.', 2),
  ('luke-watchfulness-4', 'luke-watchfulness', 'WATCH YE THEREFORE AND PRAY ALWAYS', 'Command to be counted worthy to escape and stand before the Son of man.', 'Luke 21:36 — Watch ye therefore, and pray always', 'Luke 21:36', 'Watch ye therefore, and pray always, that ye may be accounted worthy to escape all these things that shall come to pass, and to stand before the Son of man.', 'Prayer keeps the soul alert for the unexpected hour of the Advent.', 3),
  ('luke-watchfulness-5', 'luke-watchfulness', 'YOUR REDEMPTION DRAWETH NIGH', 'When these things begin to come to pass, look up.', 'Luke 21:28 — your redemption draweth nigh', 'Luke 21:28', '; for your redemption draweth nigh. 29 And he spake to them a parable; Behold the fig tree, and all the trees; 30 When they now shoot forth, ye see and know', 'Crisis for the world is hope for those whose citizenship is in heaven.', 4),
  ('acts-restoration-1', 'acts-restoration', 'SUDDENLY THERE CAME A SOUND FROM HEAVEN', 'Rushing mighty wind filled the house where disciples waited.', 'Acts 2:2 — suddenly there came a sound from heaven', 'Acts 2:2', 'And suddenly there came a sound from heaven as of a rushing mighty wind, and it filled all the house where they were sitting. 3 And there appeared unto them cloven', 'The early rain began with audible heaven-sent power, not human organization.', 0),
  ('acts-restoration-2', 'acts-restoration', 'CLOVEN TONGUES LIKE AS OF FIRE', 'Sat upon each of them when the Spirit was poured out.', 'Acts 2:3 — cloven tongues like as of fire', 'Acts 2:3', 'And there appeared unto them cloven tongues like as of fire, and it sat upon each of them. 4 And they were all filled with the Holy Ghost, and began to speak with other tongues, as', 'Fire symbolizes purification and proclamation accompanying Spirit baptism.', 1),
  ('acts-restoration-3', 'acts-restoration', 'TIMES OF RESTITUTION OF ALL THINGS', 'Peter said heaven must receive Christ until all things restored.', 'Acts 3:21 — times of restitution of all things', 'Acts 3:21', 'Of restitution of all things, which God hath spoken by the mouth of all his holy prophets since the world began. 22 For Moses truly said unto the fathers,', 'History moves toward restoration of Eden''s order through Christ''s reign.', 2),
  ('acts-restoration-4', 'acts-restoration', 'A PROPHET SHALL THE LORD YOUR GOD RAISE UP', 'Moses'' prophecy of a Prophet the people must hear.', 'Acts 3:22 — A prophet shall the Lord your God raise up unto you of your ', 'Acts 3:22', 'For Moses truly said unto the fathers, A prophet shall the Lord your God raise up unto you of your brethren, like unto me; him shall ye hear in all things whatsoever he shall say unto you. 23 And it shall come to pass, that every soul, which', 'Christ fulfills Moses'' prediction — rejecting Him repeats Israel''s fatal error.', 3),
  ('acts-restoration-5', 'acts-restoration', 'REPENT YE THEREFORE AND BE CONVERTED', 'Peter''s call that sins may be blotted out when refreshing comes.', 'Acts 3:19 — Repent ye therefore, and be converted', 'Acts 3:19', 'Repent ye therefore, and be converted, that your sins may be blotted out, when the times of refreshing shall come from the presence of the Lord; 20 And he shall', 'Revival precedes latter rain — conversion opens the door to Spirit refreshing.', 4),
  ('romans-gospel-1', 'romans-gospel', 'NOT ASHAMED OF THE GOSPEL OF CHRIST', 'Paul''s theme — power of God unto salvation to every believer.', 'Romans 1:16 — I am not ashamed of the gospel of Christ', 'Romans 1:16', 'For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek. 17 For', 'End-time witnesses proclaim the same gospel Paul defended in Rome.', 0),
  ('romans-gospel-2', 'romans-gospel', 'THE JUST SHALL LIVE BY FAITH', 'Habakkuk''s line Paul quotes when the righteousness of God is revealed from faith to faith.', 'Romans 1:17 — The just shall live by faith', 'Romans 1:17', 'The just shall live by faith. 18 For the wrath of God is revealed from heaven against all ungodliness and unrighteousness of men, who hold the truth', 'Habakkuk''s motto became the Reformation and remains the remnant''s foundation.', 1),
  ('romans-gospel-3', 'romans-gospel', 'ALL HAVE SINNED AND COME SHORT OF THE GLORY OF GOD', 'Universal need of grace — none righteous, no not one.', 'Romans 3:23 — all have sinned, and come short of the glory of God', 'Romans 3:23', 'Have sinned, and come short of the glory of God; 24 Being justified freely by his grace through the redemption that is in Christ Jesus: Romans 3 2488 Romans 3', 'Judgment truth begins with honest confession of universal sinfulness.', 2),
  ('romans-gospel-4', 'romans-gospel', 'THE WAGES OF SIN IS DEATH', 'But gift of God is eternal life through Jesus Christ.', 'Romans 6:23 — The wages of sin is death', 'Romans 6:23', 'For the wages of sin is death; but the gift of God is eternal life through Jesus Christ our Lord. 2495 Romans 6', 'Two destinies — earned death or gifted life through Christ.', 3),
  ('romans-gospel-5', 'romans-gospel', 'THE WHOLE CREATION GROANETH AND TRAVAILETH IN PAIN TOGETHER', 'Paul describes creation''s shared longing for the revealing of the sons of God.', 'Romans 8:22 — the whole creation groaneth and travaileth in pain together', 'Romans 8:22', 'For we know that the whole creation groaneth and travaileth in pain together until now. 23 And not only they, but ourselves also, which have the firstfruits of the Spirit, even we ourselves groan within', 'Nature itself testifies that this world is bound for liberation at the Advent.', 4),
  ('first-corinthians-resurrection-1', 'first-corinthians-resurrection', 'AT THE LAST TRUMP', 'Dead raised incorruptible when trumpet sounds at end.', '1 Corinthians 15:52 — the trumpet shall sound', '1 Corinthians 15:52', 'In a moment, in the twinkling of an eye, at the last trump: for the trumpet shall sound, and the dead shall be raised incorruptible, and we shall be changed.', 'Paul links resurrection hope to the same trumpet imagery used in Revelation.', 0),
  ('first-corinthians-resurrection-2', 'first-corinthians-resurrection', 'VICTORY THROUGH OUR LORD JESUS CHRIST', 'Paul''s thanksgiving for triumph God gives through Christ.', '1 Corinthians 15:57 — thanks be to God, which giveth us the victory', '1 Corinthians 15:57', 'But thanks be to God, which giveth us the victory through our Lord Jesus Christ. 58 Therefore, my beloved brethren, be ye stedfast, unmovable, always abounding in the work', 'Resurrection is not wishful thinking but guaranteed triumph through Christ.', 1),
  ('first-corinthians-resurrection-3', 'first-corinthians-resurrection', 'UNTO THE JEWS A STUMBLINGBLOCK', 'Preaching Christ crucified — foolishness to Greeks, power to believers.', '1 Corinthians 1:23 — Christ crucified, unto the Jews a stumblingblock', '1 Corinthians 1:23', 'Christ crucified, unto the Jews a stumblingblock, and unto the Greeks foolishness; 24 But unto them which are called, both Jews and Greeks, Christ the power of God, and', 'The cross remains the dividing line between human wisdom and saving power.', 2),
  ('first-corinthians-resurrection-4', 'first-corinthians-resurrection', 'I SHEW YOU A MYSTERY', 'We shall not all sleep but be changed in a moment.', '1 Corinthians 15:51 — I shew you a mystery', '1 Corinthians 15:51', 'Behold, I shew you a mystery; We shall not all sleep, but we shall all be changed, 52 In a moment, in the twinkling of an eye, at the last trump: for', 'Living saints experience translation — a distinct end-time promise.', 3),
  ('first-corinthians-resurrection-5', 'first-corinthians-resurrection', 'THIS CORRUPTIBLE MUST PUT ON INCORRUPTION', 'Mortal must put on immortality when victory swallows death.', '1 Corinthians 15:53 — corruptible must put on incorruption', '1 Corinthians 15:53', 'For this corruptible must put on incorruption, and this mortal must put on immortality. 54 So when this corruptible shall have put on incorruption, and this mortal shall', 'Glorified bodies complete salvation at the last day.', 4),
  ('ephesians-armour-1', 'ephesians-armour', 'WE WRESTLE NOT AGAINST FLESH AND BLOOD', 'Our struggle is against principalities and spiritual wickedness in high places.', 'Ephesians 6:12 — we wrestle not against flesh and blood', 'Ephesians 6:12', 'For we wrestle not against flesh and blood, but against principalities, against powers, against the rulers of the darkness of this world, against spiritual wickedness', 'Prophetic conflict is ultimately spiritual, though it plays out in history.', 0),
  ('ephesians-armour-2', 'ephesians-armour', 'HAVING YOUR LOINS GIRT ABOUT WITH TRUTH', 'First piece of armour — stand therefore having truth about the loins.', 'Ephesians 6:14 — having your loins girt about with truth', 'Ephesians 6:14', 'Stand therefore, having your loins girt about with truth, and having on the breastplate of righteousness; 15 And your feet shod with the preparation of the gospel of peace; 16 Above', 'Doctrinal integrity holds every other piece of Christian armor in place.', 1),
  ('ephesians-armour-3', 'ephesians-armour', 'SHIELD OF FAITH', 'Quenches all the fiery darts of the wicked one.', 'Ephesians 6:16 — shield of faith', 'Ephesians 6:16', '; 16 Above all, taking the shield of faith, wherewith ye shall be able to quench all the fiery darts of the wicked. 17 And take the helmet of salvation, and the sword', 'Trust in God''s word extinguishes Satan''s accusations and temptations.', 2),
  ('ephesians-armour-4', 'ephesians-armour', 'TAKE THE HELMET OF SALVATION AND THE SWORD OF THE SPIRIT', 'Protects the mind in the battle for the soul.', 'Ephesians 6:17 — take the helmet of salvation, and the sword of the Spirit', 'Ephesians 6:17', 'And take the helmet of salvation, and the sword of the Spirit, which is the word of God: 18 Praying always with all prayer and supplication in the Spirit, and watching thereunto with', 'Assurance of salvation guards against despair in the time of trouble.', 3),
  ('ephesians-armour-5', 'ephesians-armour', 'SWORD OF THE SPIRIT WHICH IS THE WORD OF GOD', 'The word of God — only offensive weapon listed.', 'Ephesians 6:17 — sword of the Spirit, which is the word of God', 'Ephesians 6:17', 'And take the helmet of salvation, and the sword of the Spirit, which is the word of God: 18 Praying always with all prayer and supplication in the Spirit, and watching thereunto with all perseverance and supplication', 'Scripture is both shield and weapon in the great controversy.', 4),
  ('thessalonians-coming-1', 'thessalonians-coming', 'COMFORT ONE ANOTHER WITH THESE WORDS', 'Words about those asleep — sorrow not as others without hope.', '1 Thessalonians 4:18 — comfort one another with these words', '1 Thessalonians 4:18', 'Wherefore comfort one another with these words. 1 Thessalonians 4 2606 1 Thessalonians 4', 'Advent hope transforms grief into anticipation for reunited saints.', 0),
  ('thessalonians-coming-2', 'thessalonians-coming', 'THE DAY OF THE LORD SO COMETH AS A THIEF IN THE NIGHT', 'Day of the Lord comes when peace and safety are declared.', '1 Thessalonians 5:2 — the day of the Lord so cometh as a thief in the night', '1 Thessalonians 5:2', 'For yourselves know perfectly that the day of the Lord so cometh as a thief in the night. 3 For when they shall say, Peace and safety; then sudden destruction cometh upon them, as travail upon a woman with child;', 'Suddenness catches the unprepared; watchfulness marks the faithful.', 1),
  ('thessalonians-coming-3', 'thessalonians-coming', 'THAT MAN OF SIN BE REVEALED', 'Son of perdition exalts himself above all that is called God.', '2 Thessalonians 2:3 — that man of sin be revealed', '2 Thessalonians 2:3', 'Man of sin be revealed, the son of perdition; 4 Who opposeth and exalteth himself above all that is called God, or that is worshipped; so that', 'Paul foresaw a developing apostasy before Christ''s return.', 2),
  ('thessalonians-coming-4', 'thessalonians-coming', 'HE WHO NOW LETTETH WILL LET', 'Something restrains until the wicked one is taken out of the way.', '2 Thessalonians 2:7 — he who now letteth will let', '2 Thessalonians 2:7', 'For the mystery of iniquity doth already work: only he who now letteth will let, until he be taken out of the way. 8 And then shall that Wicked be revealed, whom the Lord shall consume with the spirit', 'Prophetic timing involves restraining forces removed before final deception.', 3),
  ('thessalonians-coming-5', 'thessalonians-coming', 'STAND FAST AND HOLD THE TRADITIONS', 'Paul urges steadfastness in taught word whether by epistle or speech.', '2 Thessalonians 2:15 — stand fast, and hold the traditions', '2 Thessalonians 2:15', 'Therefore, brethren, stand fast, and hold the traditions which ye have been taught, whether by word, or our epistle. 16 Now our Lord Jesus Christ himself, and God, even our Father,', 'End-time stability comes from holding apostolic teaching, not novel theories.', 4),
  ('second-peter-day-1', 'second-peter-day', 'THERE SHALL COME IN THE LAST DAYS SCOFFERS', 'Mockers ask where is promise of His coming since fathers fell asleep.', '2 Peter 3:3 — there shall come in the last days scoffers', '2 Peter 3:3', 'Knowing this first, that there shall come in the last days scoffers, walking after their own lusts, 4 And saying, Where is the promise of his coming? for since the fathers fell asleep, all', 'Skepticism about the Advent is itself a sign of the last days.', 0),
  ('second-peter-day-2', 'second-peter-day', 'ONE DAY IS WITH THE LORD AS A THOUSAND YEARS', 'Peter''s perspective on divine timing versus human calendars.', '2 Peter 3:8 — one day is with the Lord as a thousand years', '2 Peter 3:8', 'But, beloved, be not ignorant of this one thing, that one day is with the Lord as a thousand years, and a thousand years as one day. 9 The Lord is not slack concerning his promise, as some men count slackness; but is longsuffering', 'Apparent delay is patience, not broken promise.', 1),
  ('second-peter-day-3', 'second-peter-day', 'ELEMENTS SHALL MELT WITH FERVENT HEAT', 'Heavens pass away with great noise at day of God.', '2 Peter 3:10 — elements shall melt with fervent heat', '2 Peter 3:10', '; in the which the heavens shall pass away with a great noise, and the elements shall melt with fervent heat, the earth also and the works that are therein shall be burned up. 11 Seeing then that all these things shall be dissolved,', 'Earth''s purification by fire precedes the new creation.', 2),
  ('second-peter-day-4', 'second-peter-day', 'NEW HEAVENS AND A NEW EARTH WHEREIN DWELLETH RIGHTEOUSNESS', 'Peter''s promise beyond the day of the Lord for the home of the righteous.', '2 Peter 3:13 — new heavens and a new earth, wherein dwelleth righteousness', '2 Peter 3:13', 'Heavens and a new earth, wherein dwelleth righteousness. 14 Wherefore, beloved, seeing that ye look for such things, be diligent that ye may be found of him in peace, without spot,', 'Peter''s hope matches Revelation''s — righteousness fills remade creation.', 3),
  ('second-peter-day-5', 'second-peter-day', 'GROW IN GRACE AND IN THE KNOWLEDGE OF OUR LORD', 'Final exhortation while waiting for day of God.', '2 Peter 3:18 — grow in grace, and in the knowledge of our Lord', '2 Peter 3:18', 'But grow in grace, and in the knowledge of our Lord and Saviour Jesus Christ. To him be glory both now and for ever. Amen. 2680 2 Peter 3', 'Waiting time is growth time — not idle speculation.', 4),
  ('rev-throne-1', 'rev-throne', 'A THRONE WAS SET IN HEAVEN', 'John saw one sitting on the throne with emerald rainbow round about.', 'Revelation 4:2 — a throne was set in heaven', 'Revelation 4:2', 'And immediately I was in the spirit: and, behold, a throne was set in heaven, and one sat on the throne. 3 And he that sat was to look upon like a jasper and a sardine stone: and there was a rainbow', 'History''s conflicts unfold before a occupied throne — God still reigns.', 0),
  ('rev-throne-2', 'rev-throne', 'FOUR AND TWENTY ELDERS', 'They cast crowns before the throne and worship Him that lives forever.', 'Revelation 4:10 — four and twenty elders', 'Revelation 4:10', 'And twenty elders sitting, clothed in white raiment; and they had on their heads crowns of gold. 5 And out of the throne proceeded lightnings', 'Redeemed representatives join heaven''s council worshipping the Creator.', 1),
  ('rev-throne-3', 'rev-throne', 'FOUR BEASTS FULL OF EYES BEFORE AND BEHIND', 'Each unlike the other — lion, calf, man, flying eagle.', 'Revelation 4:6 — four beasts full of eyes before and behind', 'Revelation 4:6', 'Beasts full of eyes before and behind. 7 And the first beast was like a lion, and the second beast like a calf, and the third beast had a face as a man, and the', 'Heaven''s intelligence covers earth with vigilant praise day and night.', 2),
  ('rev-throne-4', 'rev-throne', 'HOLY HOLY HOLY LORD GOD ALMIGHTY', 'Beasts rest not saying Holy, holy, holy, Lord God Almighty.', 'Revelation 4:8 — Holy, holy, holy, Lord God Almighty', 'Revelation 4:8', '; and they were full of eyes within: and they rest not day and night, saying, Holy, holy, holy, Lord God Almighty, which was, and is, and is to come. 9 And when those beasts give glory and honour and thanks to him that sat on the throne,', 'Isaiah''s sanctuary cry fills heaven — holiness is the atmosphere of God''s court.', 3),
  ('rev-throne-5', 'rev-throne', 'THOU ART WORTHY O LORD', 'Worthy art thou to receive glory for thou hast created all things.', 'Revelation 4:11 — thou art worthy, O Lord, to receive glory', 'Revelation 4:11', 'Thou art worthy, O Lord, to receive glory and honour and power: for thou hast created all things, and for thy pleasure they are and were created. Revelation 4 2704', 'Creation worship anchors end-time message against evolution and secularism.', 4),
  ('rev-144000-1', 'rev-144000', 'SEALED THE SERVANTS OF OUR GOD IN THEIR FOREHEADS', 'Angels hold back the winds until God''s servants receive His seal.', 'Revelation 7:3 — sealed the servants of our God in their foreheads', 'Revelation 7:3', 'Sealed the servants of our God in their foreheads. 4 And I heard the number of them which were sealed: and there were sealed an hundred and forty and four thousand of all', 'Sealing is intellectual and spiritual loyalty fixed before final plagues.', 0),
  ('rev-144000-2', 'rev-144000', 'HURT NOT THE EARTH NEITHER THE SEA', 'Four angels restrained until sealing complete.', 'Revelation 7:3 — Hurt not the earth, neither the sea', 'Revelation 7:3', 'Hurt not the earth, neither the sea, nor the trees, till we have sealed the servants of our God in their foreheads. 4 And I heard the number of them which were', 'Mercy''s bounds remain until God''s people are prepared.', 1),
  ('rev-144000-3', 'rev-144000', 'AN HUNDRED AND FORTY AND FOUR THOUSAND', 'Multitude sealed — symbolic completeness from Israel''s tribes.', 'Revelation 7:4 — an hundred and forty and four thousand of all the tribes', 'Revelation 7:4', 'And I heard the number of them which were sealed: and there were sealed an hundred and forty and four thousand of all the tribes of the children of Israel. 5 Of the tribe of Juda were sealed twelve thousand. Of the tribe of Reuben were sealed twelve', 'The remnant represents perfect spiritual Israel, not ethnic limitation.', 2),
  ('rev-144000-4', 'rev-144000', 'A GREAT MULTITUDE WHICH NO MAN COULD NUMBER', 'White-robed multitude from all nations before the throne.', 'Revelation 7:9 — a great multitude, which no man could number', 'Revelation 7:9', 'After this I beheld, and, lo, a great multitude, which no man could number, of all nations, and kindreds, and people, and tongues, stood before the throne, and before the Lamb, clothed with white', 'Beyond the symbolic 144,000 stands an innumerable harvest of saved.', 3),
  ('rev-144000-5', 'rev-144000', 'WASHED THEIR ROBES AND MADE THEM WHITE', 'Tribulation saints make their garments white in the Lamb.', 'Revelation 7:14 — washed their robes, and made them white in the blood of the ', 'Revelation 7:14', 'Washed their robes, and made them white in the blood of the Lamb. 15 Therefore are they before the throne of God, and serve him day and night in his temple: and he that sitteth on the throne', 'Tribulation saints reach glory through Lamb''s blood, not human merit.', 4),
  ('rev-witnesses-1', 'rev-witnesses', 'MY TWO WITNESSES', 'They prophesy twelve hundred sixty days clothed in sackcloth.', 'Revelation 11:3 — my two witnesses', 'Revelation 11:3', 'And I will give power unto my two witnesses, and they shall prophesy a thousand two hundred and threescore days, clothed in sackcloth. 4 These are the two olive trees,', 'Scripture and Spirit testify through prophetic periods of oppression.', 0),
  ('rev-witnesses-2', 'rev-witnesses', 'TWO OLIVE TREES AND THE TWO CANDLESTICKS', 'Standing before the God of the whole earth.', 'Revelation 11:4 — two olive trees, and the two candlesticks', 'Revelation 11:4', 'These are the two olive trees, and the two candlesticks standing before the God of the earth. 5 And if any man will hurt them, fire proceedeth out of their mouth, and devoureth', 'Zechariah''s imagery links oil of Spirit with lamp of word.', 1),
  ('rev-witnesses-3', 'rev-witnesses', 'FIRE PROCEEDETH OUT OF THEIR MOUTH', 'How the two witnesses answer those who would hurt them.', 'Revelation 11:5 — fire proceedeth out of their mouth', 'Revelation 11:5', 'And if any man will hurt them, fire proceedeth out of their mouth, and devoureth their enemies: and if any man will hurt them, he must in this manner be killed. 6 These have power to shut', 'God''s word through witnesses consumes opposition as Jeremiah foretold.', 2),
  ('rev-witnesses-4', 'rev-witnesses', 'DEAD BODIES SHALL LIE IN THE STREET', 'Beast kills witnesses; bodies lie in street of great city.', 'Revelation 11:8 — dead bodies shall lie in the street', 'Revelation 11:8', 'And their dead bodies shall lie in the street of the great city, which spiritually is called Sodom and Egypt, where also our Lord was crucified. 9 And they of the people', 'Temporary suppression of testimony precedes dramatic vindication.', 3),
  ('rev-witnesses-5', 'rev-witnesses', 'SPIRIT OF LIFE FROM GOD ENTERED INTO THEM', 'Breath enters witnesses; great fear falls on beholders.', 'Revelation 11:11 — Spirit of life from God entered into them', 'Revelation 11:11', 'And after three days and an half the Spirit of life from God entered into them, and they stood upon their feet; and great fear fell upon them which saw them. 12 And they heard a great voice from heaven', 'Revived testimony after apparent defeat marks latter rain power.', 4),
  ('rev-woman-dragon-1', 'rev-woman-dragon', 'A GREAT RED DRAGON', 'Seven heads and ten horns — old serpent called Devil and Satan.', 'Revelation 12:3 — a great red dragon', 'Revelation 12:3', 'And there appeared another wonder in heaven; and behold a great red dragon, having seven heads and ten horns, and seven crowns upon his heads. 4 And his tail drew the third part of the stars of heaven,', 'Behind earthly persecution stands the dragon who hates the woman''s seed.', 0),
  ('rev-woman-dragon-2', 'rev-woman-dragon', 'MICHAEL AND HIS ANGELS FOUGHT', 'War in heaven; dragon cast out with his angels.', 'Revelation 12:7 — Michael and his angels fought against the dragon', 'Revelation 12:7', 'And there was war in heaven: Michael and his angels fought against the dragon; and the dragon fought and his angels, 8 And prevailed not; neither was their place found any more in heaven. 9 And the great', 'Cosmic conflict intensifies as probation nears its close.', 1),
  ('rev-woman-dragon-3', 'rev-woman-dragon', 'ACCUSED THEM BEFORE OUR GOD DAY AND NIGHT', 'Heaven''s courtroom charge against the dragon cast down.', 'Revelation 12:10 — accused them before our God day and night', 'Revelation 12:10', 'Accused them before our God day and night. 11 And they overcame him by the blood of the Lamb, and by the word of their testimony; and they loved not their lives unto', 'Nearness of Advent means Satan''s accusations increase but are overcome by the Lamb.', 2),
  ('rev-woman-dragon-4', 'rev-woman-dragon', 'WILDERNESS WHERE SHE HATH A PLACE PREPARED', 'Woman fled where she is nourished twelve hundred sixty days.', 'Revelation 12:6 — wilderness, where she hath a place prepared of God', 'Revelation 12:6', 'And the woman fled into the wilderness, where she hath a place prepared of God, that they should feed her there a thousand two hundred and threescore days. 7 And there was war in heaven: Michael and', 'God sustains the church through prophetic periods of hiding and persecution.', 3),
  ('rev-woman-dragon-5', 'rev-woman-dragon', 'THE EARTH OPENED HER MOUTH', 'Earth helped woman and swallowed flood from dragon''s mouth.', 'Revelation 12:16 — the earth opened her mouth, and swallowed up the flood', 'Revelation 12:16', 'And the earth helped the woman, and the earth opened her mouth, and swallowed up the flood which the dragon cast out of his mouth. Revelation 12 2715 Revelation 12', 'Providence shields the remnant when human and demonic forces combine.', 4),
  ('rev-harvest-1', 'rev-harvest', 'EVERLASTING GOSPEL TO PREACH', 'Angel with gospel to every nation, kindred, tongue, and people.', 'Revelation 14:6 — everlasting gospel to preach unto them that dwell on the ear', 'Revelation 14:6', 'And I saw another angel fly in the midst of heaven, having the everlasting gospel to preach unto them that dwell on the earth, and to every nation, and kindred, and tongue, and people, 7 Saying with a loud voice, Fear God, and give glory to him;', 'First angel''s message is gospel-centered, not merely judgment.', 0),
  ('rev-harvest-2', 'rev-harvest', 'FEAR GOD AND GIVE GLORY TO HIM', 'First angel''s call to worship the Creator in the hour of judgment.', 'Revelation 14:7 — Fear God, and give glory to him', 'Revelation 14:7', 'Saying with a loud voice, Fear God, and give glory to him; for the hour of his judgment is come: and worship him that made heaven, and earth, and the sea, and the fountains of waters.', 'Creator worship is the answer to evolutionary and spiritualistic deception.', 1),
  ('rev-harvest-3', 'rev-harvest', 'PATIENCE OF THE SAINTS', 'Here are they that keep commandments and faith of Jesus.', 'Revelation 14:12 — Here is the patience of the saints', 'Revelation 14:12', 'Here is the patience of the saints: here are they that keep the commandments of God, and the faith of Jesus. 13 And I heard a voice from heaven saying unto', 'Remnant identity combines law and gospel — commandments and Jesus'' faith.', 2),
  ('rev-harvest-4', 'rev-harvest', 'ONE SAT LIKE UNTO THE SON OF MAN', 'Sitting on white cloud with golden crown and sharp sickle.', 'Revelation 14:14 — upon the cloud one sat like unto the Son of man', 'Revelation 14:14', 'And I looked, and behold a white cloud, and upon the cloud one sat like unto the Son of man, having on his head a golden crown, and in his hand a sharp sickle. 15 And another angel came out of the temple, crying', 'Harvest imagery points to closing work separating wheat from tares.', 3),
  ('rev-harvest-5', 'rev-harvest', 'WINEPRESS WAS TRODDEN WITHOUT THE CITY', 'Blood to horses'' bridles for thousand six hundred furlongs.', 'Revelation 14:20 — winepress was trodden without the city', 'Revelation 14:20', 'And the winepress was trodden without the city, and blood came out of the winepress, even unto the horse bridles, by the space of a thousand and six hundred furlongs.', 'Judgment on oppressors follows gospel rejection.', 4),
  ('rev-plagues-1', 'rev-plagues', 'SEVEN GOLDEN VIALS FULL OF THE WRATH OF GOD', 'Seven angels with seven plagues — last plagues filled with wrath of God.', 'Revelation 15:7 — seven golden vials full of the wrath of God', 'Revelation 15:7', 'And one of the four beasts gave unto the seven angels seven golden vials full of the wrath of God, who liveth for ever and ever. 8 And the temple was filled with smoke from the glory of God, and from his power; and no', 'Final judgments fall without mixture of mercy on hardened rebels.', 0),
  ('rev-plagues-2', 'rev-plagues', 'NOISOME AND GRIEVOUS SORE', 'First vial upon men which had mark of beast and worshipped image.', 'Revelation 16:2 — noisome and grievous sore', 'Revelation 16:2', 'And the first went, and poured out his vial upon the earth; and there fell a noisome and grievous sore upon the men which had the mark of the beast, and upon them which worshipped his image. 3 And the second angel poured out', 'Plagues target allegiance to the beast system, not random suffering.', 1),
  ('rev-plagues-3', 'rev-plagues', 'POURED OUT HIS VIAL UPON THE SEA', 'Second angel turns sea to blood as of a dead man.', 'Revelation 16:3 — poured out his vial upon the sea', 'Revelation 16:3', 'And the second angel poured out his vial upon the sea; and it became as the blood of a dead man: and every living soul died in the sea. 4 And the third angel poured out his vial', 'Creation itself bears witness against rebellion in the plague era.', 2),
  ('rev-plagues-4', 'rev-plagues', 'THE WATER THEREOF WAS DRIED UP', 'Sixth vial prepares way for kings of the east.', 'Revelation 16:12 — Euphrates; and the water thereof was dried up', 'Revelation 16:12', 'And the sixth angel poured out his vial upon the great river Euphrates; and the water thereof was dried up, that the way of the kings of the east might be prepared. 13 And I saw three unclean spirits like frogs come out of the', 'Prophetic geography symbolizes removal of barriers before final gathering.', 3),
  ('rev-plagues-5', 'rev-plagues', 'AND THE SEVENTH ANGEL POURED OUT HIS VIAL INTO THE AIR', 'Great voice from throne declares completion when seventh vial poured.', 'Revelation 16:17 — And the seventh angel poured out his vial into the air', 'Revelation 16:17', 'And the seventh angel poured out his vial into the air; and there came a great voice out of the temple of heaven, from the throne, saying, It is done. 18 And there were voices,', 'Heaven announces the end of mercy''s mixed cup — probation closed.', 4),
  ('rev-harlot-1', 'rev-harlot', 'MYSTERY BABYLON THE GREAT', 'Woman on scarlet beast full of names of blasphemy.', 'Revelation 17:5 — MYSTERY, BABYLON THE GREAT', 'Revelation 17:5', 'MYSTERY, BABYLON THE GREAT, THE MOTHER OF HARLOTS AND ABOMINATIONS OF THE EARTH. 6 And I saw the woman drunken with the blood of the saints, and with', 'Religious apostasy rides political power in end-time coalition.', 0),
  ('rev-harlot-2', 'rev-harlot', 'DRUNKEN WITH THE BLOOD OF THE SAINTS', 'The woman is intoxicated by martyrdom of Jesus'' people.', 'Revelation 17:6 — drunken with the blood of the saints', 'Revelation 17:6', 'And I saw the woman drunken with the blood of the saints, and with the blood of the martyrs of Jesus: and when I saw her, I wondered with great admiration. 7 And the angel said', 'Persecution history identifies systems hostile to commandment keepers.', 1),
  ('rev-harlot-3', 'rev-harlot', 'THE TEN HORNS WHICH THOU SAWEST UPON THE BEAST', 'Horns hate harlot and make her desolate and naked.', 'Revelation 17:16 — the ten horns which thou sawest upon the beast', 'Revelation 17:16', 'And the ten horns which thou sawest upon the beast, these shall hate the whore, and shall make her desolate and naked, and shall eat her flesh, and burn her with fire. Revelation', 'Earthly allies eventually turn on ecclesiastical Babylon.', 2),
  ('rev-harlot-4', 'rev-harlot', 'BABYLON THE GREAT IS FALLEN IS FALLEN', 'Babylon the great is fallen, is fallen — before second angel''s echo.', 'Revelation 18:2 — Babylon the great is fallen, is fallen', 'Revelation 18:2', 'And he cried mightily with a strong voice, saying, Babylon the great is fallen, is fallen, and is become the habitation of devils, and the hold of every foul spirit, and a cage of every unclean and hateful bird.', 'Moral fall precedes political collapse of confused religious systems.', 3),
  ('rev-harlot-5', 'rev-harlot', 'THE MERCHANDISE OF GOLD AND SILVER', 'Kings of earth mourn when Babylon''s commerce ceases in one hour.', 'Revelation 18:12 — The merchandise of gold, and silver', 'Revelation 18:12', '; for no man buyeth their merchandise any more: 12 The merchandise of gold, and silver, and precious stones, and of pearls, and fine linen, and purple, and silk, and scarlet, and all thyine wood, and all manner', 'Economic entanglement with Babylon makes separation costly but necessary.', 4),
  ('rev-victory-1', 'rev-victory', 'CALLED FAITHFUL AND TRUE', 'Heaven opens — the white-horse Rider judges and makes war in righteousness.', 'Revelation 19:11 — called Faithful and True', 'Revelation 19:11', '; and he that sat upon him was called Faithful and True, and in righteousness he doth judge and make war. 12 His eyes were as a flame of fire, and on his head were many crowns;', 'Christ returns as warrior-king, not secret rapture thief only.', 0),
  ('rev-victory-2', 'rev-victory', 'THE ARMIES WHICH WERE IN HEAVEN FOLLOWED HIM', 'Armies on white horses clothed in fine linen follow the Word of God.', 'Revelation 19:14 — the armies which were in heaven followed him', 'Revelation 19:14', 'And the armies which were in heaven followed him upon white horses, clothed in fine linen, white and clean. 15 And out of his mouth goeth a sharp sword, that with it he', 'Saints join the final campaign as glorified companions of Christ.', 1),
  ('rev-victory-3', 'rev-victory', 'THE MARRIAGE OF THE LAMB IS COME', 'Wife made herself ready — fine linen is righteousness of saints.', 'Revelation 19:7 — the marriage of the Lamb is come', 'Revelation 19:7', 'Let us be glad and rejoice, and give honour to him: for the marriage of the Lamb is come, and his wife hath made herself ready. 8 And to her was granted that she should be arrayed in fine linen, clean and white:', 'Corporate readiness of church precedes eternal union with Bridegroom.', 2),
  ('rev-victory-4', 'rev-victory', 'CAST ALIVE INTO A LAKE OF FIRE BURNING WITH BRIMSTONE', 'Fate of the beast and false prophet when the Rider conquers.', 'Revelation 19:20 — cast alive into a lake of fire burning with brimstone', 'Revelation 19:20', 'These both were cast alive into a lake of fire burning with brimstone. 21 And the remnant were slain with the sword of him that sat upon the horse, which sword proceeded out of his mouth: and', 'Judgment on leaders of rebellion precedes broader final destruction.', 3),
  ('rev-victory-5', 'rev-victory', 'CAST INTO THE LAKE OF FIRE', 'After the thousand years, the deceiver is thrown where the beast and false prophet are.', 'Revelation 20:10 — devil that deceived them was cast into the lake of fire', 'Revelation 20:10', 'And the devil that deceived them was cast into the lake of fire and brimstone, where the beast and the false prophet are, and shall be tormented day and night for ever and ever. 11 And', 'Sin problem ends when author of deception is destroyed forever.', 4),
  ('rev-new-creation-1', 'rev-new-creation', 'TABERNACLE OF GOD IS WITH MEN', 'God shall dwell with them — they shall be His people.', 'Revelation 21:3 — tabernacle of God is with men', 'Revelation 21:3', 'And I heard a great voice out of heaven saying, Behold, the tabernacle of God is with men, and he will dwell with them, and they shall be his people, and God himself shall be with them, and be their God. 4 And', 'Eden lost becomes Eden restored with God living among redeemed.', 0),
  ('rev-new-creation-2', 'rev-new-creation', 'ALPHA AND OMEGA THE BEGINNING AND THE END', 'He that sat on throne — I am Alpha and Omega, the beginning and the end.', 'Revelation 21:6 — I am Alpha and Omega, the beginning and the end', 'Revelation 21:6', 'I am Alpha and Omega, the beginning and the ending, saith the Lord, which is, and which was, and which is to come, the Almighty. 9 I John, who also am your brother, and', 'Christ who started creation completes it in the new earth.', 1),
  ('rev-new-creation-3', 'rev-new-creation', 'PURE RIVER OF WATER OF LIFE', 'Clear as crystal proceeding from throne of God and of the Lamb.', 'Revelation 22:1 — pure river of water of life', 'Revelation 22:1', 'And he shewed me a pure river of water of life, clear as crystal, proceeding out of the throne of God and of the Lamb. 2 In the midst of the street of it, and on either', 'Eternal life flows from the throne — no separation from source.', 2),
  ('rev-new-creation-4', 'rev-new-creation', 'TREE OF LIFE WHICH BARE TWELVE MANNER OF FRUITS', 'Leaves for healing of nations on either side of the river.', 'Revelation 22:2 — tree of life, which bare twelve manner of fruits', 'Revelation 22:2', 'Of life, which bare twelve manner of fruits, and yielded her fruit every month: and the leaves of the tree were for the healing of the nations. 3 And there shall be', 'Access forbidden at Eden''s fall is restored for eternity.', 3),
  ('rev-new-creation-5', 'rev-new-creation', 'THE SPIRIT AND THE BRIDE SAY COME', 'Let him that heareth say Come — whosoever will take water of life freely.', 'Revelation 22:17 — the Spirit and the bride say, Come', 'Revelation 22:17', 'And the Spirit and the bride say, Come. And let him that heareth say, Come. And let him that is athirst come. And whosoever will, let him take the water of life', 'Even at Scripture''s close, gospel invitation remains open until probation ends.', 4),
  ('genesis-beginnings-1', 'genesis-beginnings', 'IN THE BEGINNING GOD CREATED', 'Opening line of Scripture establishing God as Creator.', 'Genesis 1:1 — In the beginning God created the heaven and the earth', 'Genesis 1:1', 'In the beginning God created the heaven and the earth. 2 And the earth was without form, and void; and darkness was upon the face of the deep. And the Spirit of God moved upon the face of the waters. 3 And God said, Let there be light: and th', 'Creation anchors the Sabbath and the three angels’ call to worship the Maker.', 0),
  ('genesis-beginnings-2', 'genesis-beginnings', 'GOD BLESSED THE SEVENTH DAY', 'The day God sanctified after finishing His work.', 'Genesis 2:3 — God blessed the seventh day, and sanctified it', 'Genesis 2:3', 'And God blessed the seventh day, and sanctified it: because that in it he had rested from all his work which God created and made. 4 These are the generations of the heavens and of the earth when they were created, in the day that the Lord God m', 'Sabbath is a creation memorial, not a Jewish invention.', 1),
  ('genesis-beginnings-3', 'genesis-beginnings', 'DUST THOU ART', 'Sentence on Adam after the fall — mortality announced.', 'Genesis 3:19 — dust thou art, and unto dust shalt thou return', 'Genesis 3:19', 'thou art, and unto dust shalt thou return. 20 And Adam called his wife''s name Eve; because she was the mother of all living. 21 Unto Adam also and to his wife did the Lord God make coats of skins, and clothed them. 22 And the Lord God sai', 'Death is the wage of sin; resurrection is the gift of Christ.', 2),
  ('genesis-beginnings-4', 'genesis-beginnings', 'ENMITY BETWEEN THEE AND THE WOMAN', 'First gospel promise spoken to the serpent.', 'Genesis 3:15 — enmity between thee and the woman', 'Genesis 3:15', 'Enmity between thee and the woman, and between thy seed and her seed; it shall bruise thy head, and thou shalt bruise his heel. 16 Unto the woman he said, I will greatly multiply thy sorrow and thy conception; in sorrow thou shalt bring fort', 'The great controversy began in Eden and ends with the serpent crushed.', 3),
  ('genesis-beginnings-5', 'genesis-beginnings', 'NOAH FOUND GRACE', 'Why one man was spared when the earth was filled with violence.', 'Genesis 6:8 — Noah found grace in the eyes of the LORD', 'Genesis 6:8', 'But Noah found grace in the eyes of the Lord. 9 These are the generations of Noah: Noah was a just man and perfect in his generations, and Noah walked with God. 10 And Noah begat three sons, Shem, Ham, and Japheth. 11 The earth also was corrupt be', 'As in Noah’s day, grace saves a remnant before judgment falls.', 4),
  ('exodus-sabbath-1', 'exodus-sabbath', 'REMEMBER THE SABBATH DAY', 'Opening of the fourth commandment.', 'Exodus 20:8 — Remember the sabbath day, to keep it holy', 'Exodus 20:8', 'Remember the sabbath day, to keep it holy. 9 Six days shalt thou labour, and do all thy work: 10 But the seventh day is the sabbath of the Lord thy God: in it thou shalt not do any work, thou, nor thy son, nor thy daughter, thy manservant, no', 'Remembrance of creation and redemption meet in the Sabbath command.', 0),
  ('exodus-sabbath-2', 'exodus-sabbath', 'SIX DAYS SHALT THOU LABOUR', 'Work week bounded by holy rest.', 'Exodus 20:9 — Six days shalt thou labour, and do all thy work', 'Exodus 20:9', 'Six days shalt thou labour, and do all thy work: 10 But the seventh day is the sabbath of the Lord thy God: in it thou shalt not do any work, thou, nor thy son, nor thy daughter, thy manservant, nor thy maidservant, nor thy cattle, nor thy s', 'Sabbath blessing includes faithful labor and holy rest.', 1),
  ('exodus-sabbath-3', 'exodus-sabbath', 'THE SEVENTH DAY IS THE SABBATH', 'Plain identity of the day belonging to the LORD thy God.', 'Exodus 20:10 — the seventh day is the sabbath of the LORD thy God', 'Exodus 20:10', 'Six days shalt thou labour, and do all thy work: 10 But the seventh day is the sabbath of the Lord thy God: in it thou shalt not do any work, thou, nor thy son, nor thy daughter, thy manservant, nor thy maidservant, nor thy cattle, nor thy stranger that is within thy gates: 11 For in six days the', 'God names the day; human tradition cannot rename His holy time.', 2),
  ('exodus-sabbath-4', 'exodus-sabbath', 'FOR IN SIX DAYS THE LORD', 'Creation reason attached to the Sabbath command.', 'Exodus 20:11 — For in six days the LORD made heaven and earth', 'Exodus 20:11', 'For in six days the Lord made heaven and earth, the sea, and all that in them is, and rested the seventh day: wherefore the Lord blessed the sabbath day, and hallowed it. 12 Honour thy father and thy mother: that thy days may be long upon th', 'Creator worship is the issue of the final crisis.', 3),
  ('exodus-sabbath-5', 'exodus-sabbath', 'TABLES OF STONE', 'Material on which God wrote the Ten Commandments.', 'Exodus 31:18 — tables of stone, written with the finger of God', 'Exodus 31:18', 'Tables of stone, written with the finger of God. Exodus 31 194 Exodus 31', 'The law is as enduring as the finger that wrote it.', 4),
  ('isaiah-sabbath-1', 'isaiah-sabbath', 'CALL THE SABBATH A DELIGHT', 'Isaiah’s description of true Sabbath joy.', 'Isaiah 58:13 — call the sabbath a delight', 'Isaiah 58:13', 'the sabbath a delight, the holy of the Lord, honourable; and shalt honour him, not doing thine own ways, nor finding thine own pleasure, nor speaking thine own words: Isaiah 58 1400 Isaiah 58', 'Sabbath is gift, not burden, when the heart loves the Giver.', 0),
  ('isaiah-sabbath-2', 'isaiah-sabbath', 'HOLY OF THE LORD HONOURABLE', 'How the Sabbath is to be called by those who honor God.', 'Isaiah 58:13 — the holy of the LORD, honourable', 'Isaiah 58:13', 'holy of the Lord, honourable; and shalt honour him, not doing thine own ways, nor finding thine own pleasure, nor speaking thine own words: Isaiah 58 1400 Isaiah 58', 'Reverence for God’s day reveals reverence for God’s character.', 1),
  ('isaiah-sabbath-3', 'isaiah-sabbath', 'NOT DOING THINE OWN WAYS', 'Sabbath restraint of self-seeking pleasure and speech.', 'Isaiah 58:13 — not doing thine own ways', 'Isaiah 58:13', 'doing thine own ways, nor finding thine own pleasure, nor speaking thine own words: Isaiah 58 1400 Isaiah 58', 'Holy time frees us from self to serve God and neighbor.', 2),
  ('isaiah-sabbath-4', 'isaiah-sabbath', 'THEN SHALT THOU DELIGHT THYSELF', 'Promise to those who keep Sabbath from polluting it.', 'Isaiah 58:14 — Then shalt thou delight thyself in the LORD', 'Isaiah 58:14', 'Then shalt thou delight thyself in the Lord; and I will cause thee to ride upon the high places of the earth, and feed thee with the heritage of Jacob thy father: for the mouth of the Lord hath spoken it. 1401 Isaiah 58', 'Delight in God is the reward of true Sabbath rest.', 3),
  ('isaiah-sabbath-5', 'isaiah-sabbath', 'RIDE UPON THE HIGH PLACES', 'Isaiah’s promise of elevated privilege for Sabbath keepers.', 'Isaiah 58:14 — I will cause thee to ride upon the high places of the earth', 'Isaiah 58:14', 'I will cause thee to ride upon the high places of the earth, and feed thee with the heritage of Jacob thy father: for the mouth of the Lord hath spoken it. 1401 Isaiah 58', 'Faithful loyalty is honored even when the world despises it.', 4),
  ('ezekiel-watchman-1', 'ezekiel-watchman', 'SON OF MAN I HAVE MADE THEE A WATCHMAN', 'God’s commission to Ezekiel for the house of Israel.', 'Ezekiel 3:17 — I have made thee a watchman unto the house of Israel', 'Ezekiel 3:17', 'I have made thee a watchman unto the house of Israel: therefore hear the word at my mouth, and give them warning from me. Ezekiel 3 1541 Ezekiel 3', 'Last-day messengers share the watchman’s duty to warn.', 0),
  ('ezekiel-watchman-2', 'ezekiel-watchman', 'HEAR THE WORD AT MY MOUTH', 'Source of the watchman’s message — not human opinion.', 'Ezekiel 3:17 — hear the word at my mouth, and give them warning from me', 'Ezekiel 3:17', 'the word at my mouth, and give them warning from me. Ezekiel 3 1541 Ezekiel 3', 'Authority rests in God’s word spoken in love.', 1),
  ('ezekiel-watchman-3', 'ezekiel-watchman', 'HIS BLOOD WILL I REQUIRE', 'Consequence if the watchman fails to warn the wicked.', 'Ezekiel 3:18 — his blood will I require at thine hand', 'Ezekiel 3:18', 'blood will I require at thine hand. 19 Yet if thou warn the wicked, and he turn not from his wickedness, nor from his wicked way, he shall die in his iniquity; but thou hast delivered thy soul. 20 Again, When a righteous man doth turn fro', 'Silence when truth is needed is not neutrality.', 2),
  ('ezekiel-watchman-4', 'ezekiel-watchman', 'THOU HAST DELIVERED THY SOUL', 'Result when the watchman warns even if the hearer refuses.', 'Ezekiel 3:19 — thou hast delivered thy soul', 'Ezekiel 3:19', 'hast delivered thy soul. 20 Again, When a righteous man doth turn from his righteousness, and commit iniquity, and I lay a stumblingblock before him, he shall die: because thou hast not given him warning, he shall die in his sin, and hi', 'Faithful witness frees the messenger; hearers still choose.', 3),
  ('ezekiel-watchman-5', 'ezekiel-watchman', 'I HAVE NO PLEASURE IN THE DEATH', 'God’s heart toward the wicked who turn from their way.', 'Ezekiel 33:11 — I have no pleasure in the death of the wicked', 'Ezekiel 33:11', 'I have no pleasure in the death of the wicked; but that the wicked turn from his way and live: turn ye, turn ye from your evil ways; for why will ye die, O house of Israel? 12 Therefore, thou son of man, say unto the children of thy people,', 'Judgment is real, yet God’s desire is repentance and life.', 4),
  ('daniel-one-1', 'daniel-one', 'DANIEL PURPOSED IN HIS HEART', 'Daniel’s resolve not to defile himself with the king’s meat.', 'Daniel 1:8 — Daniel purposed in his heart that he would not defile himsel', 'Daniel 1:8', 'But Daniel purposed in his heart that he would not defile himself with the portion of the king''s meat, nor with the wine which he drank: therefore he requested of the prince of the eunuchs that he might not defile himself. 9 Now God had brought', 'Character decisions made early sustain faithfulness later.', 0),
  ('daniel-one-2', 'daniel-one', 'PULSE TO EAT AND WATER TO DRINK', 'The ten-day diet request of the four Hebrews.', 'Daniel 1:12 — pulse to eat, and water to drink', 'Daniel 1:12', 'to eat, and water to drink. 13 Then let our countenances be looked upon before thee, and the countenance of the children that eat of the portion of the king''s meat: and as thou seest, deal with thy servants. 14 So he consented to them i', 'Temperance is part of last-day preparation for clear minds.', 1),
  ('daniel-one-3', 'daniel-one', 'TEN TIMES BETTER', 'How the four compared to magicians after God’s blessing.', 'Daniel 1:20 — ten times better than all the magicians', 'Daniel 1:20', 'times better than all the magicians and astrologers that were in all his realm. 21 And Daniel continued even unto the first year of king Cyrus. 1640 Daniel 1', 'God honors those who honor Him in ordinary choices.', 2),
  ('daniel-one-4', 'daniel-one', 'GOD GAVE THEM KNOWLEDGE', 'Source of the youths’ skill in learning and wisdom.', 'Daniel 1:17 — God gave them knowledge and skill in all learning', 'Daniel 1:17', 'God gave them knowledge and skill in all learning and wisdom: and Daniel had understanding in all visions and dreams. 18 Now at the end of the days that the king had said he should bring them in, then the prince of the eunuchs brought them i', 'True education unites intellect with loyalty to God.', 3),
  ('daniel-one-5', 'daniel-one', 'DANIEL CONTINUED EVEN UNTO', 'Daniel’s long service spanning multiple empires.', 'Daniel 1:21 — Daniel continued even unto the first year of king Cyrus', 'Daniel 1:21', 'And Daniel continued even unto the first year of king Cyrus. 1640 Daniel 1', 'Faithfulness is a lifetime race, not a single test.', 4),
  ('habakkuk-vision-1', 'habakkuk-vision', 'WRITE THE VISION', 'Command to make the vision plain upon tables.', 'Habakkuk 2:2 — Write the vision, and make it plain upon tables', 'Habakkuk 2:2', 'And the Lord answered me, and said, Write the vision, and make it plain upon tables, that he may run that readeth it. 3 For the vision is yet for an appointed time, but at the end it shall speak, and not lie: though it tarry, wait for it; because it will surely come, it will n', 'Prophetic truth must be clear enough to run with.', 0),
  ('habakkuk-vision-2', 'habakkuk-vision', 'THAT HE MAY RUN THAT READETH', 'Purpose of writing the vision plainly.', 'Habakkuk 2:2 — that he may run that readeth it', 'Habakkuk 2:2', 'he may run that readeth it. 3 For the vision is yet for an appointed time, but at the end it shall speak, and not lie: though it tarry, wait for it; because it will surely come, it will not tarry. 4 Behold, his soul which is lifted up is', 'Understanding moves the feet of messengers.', 1),
  ('habakkuk-vision-3', 'habakkuk-vision', 'THOUGH IT TARRY WAIT FOR IT', 'Counsel when the appointed time seems delayed.', 'Habakkuk 2:3 — though it tarry, wait for it', 'Habakkuk 2:3', 'Though it tarry, wait for it; because it will surely come, it will not tarry. 4 Behold, his soul which is lifted up is not upright in him: but the just shall live by his faith. 5 Yea also, because he transgresseth by wine, he is a proud man,', 'Delay is not denial; the vision is for an appointed time.', 2),
  ('habakkuk-vision-4', 'habakkuk-vision', 'IT WILL SURELY COME', 'Certainty of the vision’s fulfillment.', 'Habakkuk 2:3 — it will surely come, it will not tarry', 'Habakkuk 2:3', 'will surely come, it will not tarry. 4 Behold, his soul which is lifted up is not upright in him: but the just shall live by his faith. 5 Yea also, because he transgresseth by wine, he is a proud man, neither keepeth at home, who enlargeth', 'Hope holds when calendars of men fail.', 3),
  ('habakkuk-vision-5', 'habakkuk-vision', 'THE JUST SHALL LIVE BY HIS FAITH', 'Habakkuk’s line later quoted by Paul.', 'Habakkuk 2:4 — the just shall live by his faith', 'Habakkuk 2:4', 'Behold, his soul which is lifted up is not upright in him: but the just shall live by his faith. 5 Yea also, because he transgresseth by wine, he is a proud man, neither keepeth at home, who enlargeth his desire as hell, and is as death, and cannot be satisfied, but gathereth unto him all nations, and h', 'Righteousness by faith is the heartbeat of the remnant.', 4),
  ('zephaniah-day-1', 'zephaniah-day', 'THE GREAT DAY OF THE LORD', 'Zephaniah’s description of a day near and hasting greatly.', 'Zephaniah 1:14 — The great day of the LORD is near', 'Zephaniah 1:14', 'The great day of the Lord is near, it is near, and hasteth greatly, even the voice of the day of the Lord: the mighty man shall cry there bitterly. 15 That day is a day of wrath, a day of trouble and distress, a day of wasteness and desolati', 'The day of the Lord sobers every generation that hears.', 0),
  ('zephaniah-day-2', 'zephaniah-day', 'A DAY OF WRATH', 'Part of Zephaniah’s catalog of that day’s terrors.', 'Zephaniah 1:15 — That day is a day of wrath', 'Zephaniah 1:15', 'That day is a day of wrath, a day of trouble and distress, a day of wasteness and desolation, a day of darkness and gloominess, a day of clouds and thick darkness, 16 A day of the trumpet and alarm against the fenced cities, and against the', 'Judgment is real; mercy invites us before it falls.', 1),
  ('zephaniah-day-3', 'zephaniah-day', 'SEEK YE THE LORD', 'Call to the meek of the earth before the decree bring forth.', 'Zephaniah 2:3 — Seek ye the LORD, all ye meek of the earth', 'Zephaniah 2:3', 'Seek ye the Lord, all ye meek of the earth, which have wrought his judgment; seek righteousness, seek meekness: it may be ye shall be hid in the day of the Lord''S anger. 4 For Gaza shall be forsaken, and Ashkelon a desolation: they shall dri', 'Seeking God is the only safe path as the day approaches.', 2),
  ('zephaniah-day-4', 'zephaniah-day', 'SEEK RIGHTEOUSNESS SEEK MEEKNESS', 'Twin pursuits that may hide in the day of anger.', 'Zephaniah 2:3 — seek righteousness, seek meekness', 'Zephaniah 2:3', 'Seek ye the Lord, all ye meek of the earth, which have wrought his judgment; seek righteousness, seek meekness: it may be ye shall be hid in the day of the Lord''S anger. 4 For Gaza shall be forsaken, and Ashkelon a desolation: they shall drive out Ashdod at the noonday, and Ekron shall be rooted up. 5 Woe unto the inh', 'Character preparation cannot be borrowed at the last moment.', 3),
  ('zephaniah-day-5', 'zephaniah-day', 'IT MAY BE YE SHALL BE HID', 'Conditional hope for those who seek in time.', 'Zephaniah 2:3 — it may be ye shall be hid in the day of the LORD''S anger', 'Zephaniah 2:3', 'may be ye shall be hid in the day of the Lord''S anger. 4 For Gaza shall be forsaken, and Ashkelon a desolation: they shall drive out Ashdod at the noonday, and Ekron shall be rooted up. 5 Woe unto the inhabitants of the sea coast, the nati', 'Hiding in Christ is the only shelter in the final storm.', 4),
  ('matthew-signs-1', 'matthew-signs', 'THIS GOSPEL OF THE KINGDOM', 'Must be preached in all the world before the end comes.', 'Matthew 24:14 — this gospel of the kingdom shall be preached in all the worl', 'Matthew 24:14', 'And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come. 15 When ye therefore shall see the abomination of desolation, spoken of by Daniel the prophet, stand in the holy place', 'Mission finishes before history finishes.', 0),
  ('matthew-signs-2', 'matthew-signs', 'FOR A WITNESS UNTO ALL NATIONS', 'Purpose of the global gospel proclamation.', 'Matthew 24:14 — for a witness unto all nations', 'Matthew 24:14', 'And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come. 15 When ye therefore shall see the abomination of desolation, spoken of by Daniel the prophet, stand in the holy place, (whoso readeth, let him understand:) 16 Then let them which b', 'Every nation must hear a fair testimony of Christ.', 1),
  ('matthew-signs-3', 'matthew-signs', 'THEN SHALL THE END COME', 'What follows the finished witness of the gospel.', 'Matthew 24:14 — and then shall the end come', 'Matthew 24:14', 'then shall the end come. 15 When ye therefore shall see the abomination of desolation, spoken of by Daniel the prophet, stand in the holy place, (whoso readeth, let him understand:) 16 Then let them which be in Judaea flee into the mounta', 'The end is tied to mission, not to human speculation alone.', 2),
  ('matthew-signs-4', 'matthew-signs', 'AS THE DAYS OF NOE WERE', 'Jesus’ comparison for the coming of the Son of man.', 'Matthew 24:37 — as the days of Noe were, so shall also the coming of the Son', 'Matthew 24:37', 'But as the days of Noe were, so shall also the coming of the Son of man be. 38 For as in the days that were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noe entered into the ark, 39 And knew', 'Ordinary life continues until judgment suddenly closes the door.', 3),
  ('matthew-signs-5', 'matthew-signs', 'WATCH THEREFORE', 'Jesus’ command because you know not what hour your Lord comes.', 'Matthew 24:42 — Watch therefore: for ye know not what hour your Lord doth co', 'Matthew 24:42', 'Watch therefore: for ye know not what hour your Lord doth come. 43 But know this, that if the goodman of the house had known in what watch the thief would come, he would have watched, and would not have suffered his house to be broken up. 44', 'Watchfulness is love awake to the nearness of Christ.', 4),
  ('john-comfort-1', 'john-comfort', 'I WILL PRAY THE FATHER', 'Jesus’ promise to request another Comforter for the disciples.', 'John 14:16 — I will pray the Father, and he shall give you another Comfor', 'John 14:16', 'And I will pray the Father, and he shall give you another Comforter, that he may abide with you for ever; 17 Even the Spirit of truth; whom the world cannot receive, because it seeth him not, neither knoweth him: but ye know him; for he dwelleth', 'The Spirit’s presence continues Christ’s ministry until He returns.', 0),
  ('john-comfort-2', 'john-comfort', 'SPIRIT OF TRUTH', 'Title of the Comforter the world cannot receive.', 'John 14:17 — Even the Spirit of truth', 'John 14:17', 'Even the Spirit of truth; whom the world cannot receive, because it seeth him not, neither knoweth him: but ye know him; for he dwelleth with you, and shall be in you. 18 I will not leave you comfortless: I will come to you. 19 Yet a little w', 'Truth is a Person’s guidance, not mere information.', 1),
  ('john-comfort-3', 'john-comfort', 'HE WILL GUIDE YOU INTO ALL TRUTH', 'Promise of the Spirit’s teaching work.', 'John 16:13 — he will guide you into all truth', 'John 16:13', 'Howbeit when he, the Spirit of truth, is come, he will guide you into all truth: for he shall not speak of himself; but whatsoever he shall hear, that shall he speak: and he will shew you things to come. 14 He shall glorify me: for he shall receive of mine, and shall shew it unto you. 15', 'Last-day light comes through Spirit-led Scripture.', 2),
  ('john-comfort-4', 'john-comfort', 'SANCTIFY THEM THROUGH THY TRUTH', 'Jesus’ prayer for the disciples’ holiness.', 'John 17:17 — Sanctify them through thy truth: thy word is truth', 'John 17:17', 'Sanctify them through thy truth: thy word is truth. 18 As thou hast sent me into the world, even so have I also sent them into the world. 19 And for their sakes I sanctify myself, that they also might be sanctified through the truth. 20 Neithe', 'Holiness is not emotion alone; the Word shapes character.', 3),
  ('john-comfort-5', 'john-comfort', 'THY WORD IS TRUTH', 'Jesus’ definition of truth in His high-priestly prayer.', 'John 17:17 — thy word is truth', 'John 17:17', 'Sanctify them through thy truth: thy word is truth. 18 As thou hast sent me into the world, even so have I also sent them into the world. 19 And for their sakes I sanctify myself, that they also might be sanctified through the truth. 20 Neither pray I for these alone, but for', 'Scripture remains the standard when voices multiply.', 4),
  ('acts-witness-1', 'acts-witness', 'YE SHALL RECEIVE POWER', 'Promise after the Holy Ghost is come upon you.', 'Acts 1:8 — ye shall receive power, after that the Holy Ghost is come up', 'Acts 1:8', 'But ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me both in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth. 9 And when he had spoken these things, whil', 'Latter rain power finishes the Acts 1:8 commission.', 0),
  ('acts-witness-2', 'acts-witness', 'WITNESSES UNTO ME', 'What the disciples become in Jerusalem, Judea, Samaria, and beyond.', 'Acts 1:8 — ye shall be witnesses unto me', 'Acts 1:8', 'But ye shall receive power, after that the Holy Ghost is come upon you: and ye shall be witnesses unto me both in Jerusalem, and in all Judaea, and in Samaria, and unto the uttermost part of the earth. 9 And when he had spoken these things, while they beheld, he was taken up; and a cloud received him out of their si', 'Witness is identity before it is strategy.', 1),
  ('acts-witness-3', 'acts-witness', 'UNTO THE UTTERMOST PART OF THE EARTH', 'Geographic reach of the Spirit-powered commission.', 'Acts 1:8 — unto the uttermost part of the earth', 'Acts 1:8', 'the uttermost part of the earth. 9 And when he had spoken these things, while they beheld, he was taken up; and a cloud received him out of their sight. 10 And while they looked stedfastly toward heaven as he went up, behold, two men sto', 'No corner of earth is exempt from the gospel claim.', 2),
  ('acts-witness-4', 'acts-witness', 'THIS SAME JESUS', 'Angels’ assurance about the manner of Christ’s return.', 'Acts 1:11 — this same Jesus, which is taken up from you into heaven', 'Acts 1:11', 'same Jesus, which is taken up from you into heaven, shall so come in like manner as ye have seen him go into heaven. 12 Then returned they unto Jerusalem from the mount called Olivet, which is from Jerusalem a sabbath day''s journey. 13 A', 'The returning Lord is the same Jesus who ascended.', 3),
  ('acts-witness-5', 'acts-witness', 'SHALL SO COME IN LIKE MANNER', 'How Christ will return as the disciples watched Him go.', 'Acts 1:11 — shall so come in like manner as ye have seen him go into hea', 'Acts 1:11', 'so come in like manner as ye have seen him go into heaven. 12 Then returned they unto Jerusalem from the mount called Olivet, which is from Jerusalem a sabbath day''s journey. 13 And when they were come in, they went up into an upper roo', 'Literal, visible, personal return — not a secret spiritualization only.', 4),
  ('romans-righteousness-1', 'romans-righteousness', 'I AM NOT ASHAMED OF THE GOSPEL', 'Paul’s bold confession of the gospel’s power.', 'Romans 1:16 — I am not ashamed of the gospel of Christ', 'Romans 1:16', 'For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek. 17 For therein is the righteousness of God revealed from faith to faith: as it is writt', 'End-time witness needs unashamed courage.', 0),
  ('romans-righteousness-2', 'romans-righteousness', 'IT IS THE POWER OF GOD UNTO SALVATION', 'What the gospel is to everyone that believes.', 'Romans 1:16 — it is the power of God unto salvation', 'Romans 1:16', 'For I am not ashamed of the gospel of Christ: for it is the power of God unto salvation to every one that believeth; to the Jew first, and also to the Greek. 17 For therein is the righteousness of God revealed from faith to faith: as it is written, The just shall live by faith. 18 For the wr', 'Salvation is divine power applied to human need.', 1),
  ('romans-righteousness-3', 'romans-righteousness', 'THERE IS THEREFORE NOW NO CONDEMNATION', 'Status of those in Christ Jesus.', 'Romans 8:1 — There is therefore now no condemnation to them which are in ', 'Romans 8:1', 'There is therefore now no condemnation to them which are in Christ Jesus, who walk not after the flesh, but after the Spirit. 2 For the law of the Spirit of life in Christ Jesus hath made me free from the law of sin and death. 3 For what the', 'Judgment has an answer for those who abide in Christ.', 2),
  ('romans-righteousness-4', 'romans-righteousness', 'THE LAW IS HOLY', 'Paul’s verdict on the commandment after the gospel is preached.', 'Romans 7:12 — the law is holy, and the commandment holy, and just, and goo', 'Romans 7:12', 'Wherefore the law is holy, and the commandment holy, and just, and good. 13 Was then that which is good made death unto me? God forbid. But sin, that it might appear sin, working death in me by that which is good; that sin by the commandment might bec', 'Grace never makes the law sinful; it writes it on the heart.', 3),
  ('romans-righteousness-5', 'romans-righteousness', 'DO WE THEN MAKE VOID THE LAW', 'Paul’s rhetorical question after teaching justification by faith.', 'Romans 3:31 — Do we then make void the law through faith', 'Romans 3:31', 'Do we then make void the law through faith? God forbid: yea, we establish the law. 2489 Romans 3', 'Faith establishes the law; it does not cancel it.', 4),
  ('galatians-liberty-1', 'galatians-liberty', 'I AM CRUCIFIED WITH CHRIST', 'Paul’s confession of union with the crucified Lord.', 'Galatians 2:20 — I am crucified with Christ', 'Galatians 2:20', 'I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me. 21 I do not frustrate the grace of', 'Self dies so that Christ may live out His life in us.', 0),
  ('galatians-liberty-2', 'galatians-liberty', 'NEVERTHELESS I LIVE', 'Paradox of the crucified believer who still lives.', 'Galatians 2:20 — nevertheless I live; yet not I, but Christ liveth in me', 'Galatians 2:20', 'I am crucified with Christ: nevertheless I live; yet not I, but Christ liveth in me: and the life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me. 21 I do not frustrate the grace of God: for if righteousness co', 'Christian life is Christ’s life reproduced by faith.', 1),
  ('galatians-liberty-3', 'galatians-liberty', 'THE LIFE WHICH I NOW LIVE', 'How Paul lives in the flesh — by faith of the Son of God.', 'Galatians 2:20 — the life which I now live in the flesh I live by the faith o', 'Galatians 2:20', 'life which I now live in the flesh I live by the faith of the Son of God, who loved me, and gave himself for me. 21 I do not frustrate the grace of God: for if righteousness come by the law, then Christ is dead in vain. 2566 Galatians 2', 'Daily faith, not a past memory, sustains holiness.', 2),
  ('galatians-liberty-4', 'galatians-liberty', 'STAND FAST THEREFORE IN THE LIBERTY', 'Appeal not to be entangled again with the yoke of bondage.', 'Galatians 5:1 — Stand fast therefore in the liberty wherewith Christ hath ma', 'Galatians 5:1', 'Stand fast therefore in the liberty wherewith Christ hath made us free, and be not entangled again with the yoke of bondage. 2 Behold, I Paul say unto you, that if ye be circumcised, Christ shall profit you nothing. 3 For I testify again to e', 'Gospel liberty is freedom to obey from love, not license to sin.', 3),
  ('galatians-liberty-5', 'galatians-liberty', 'BY LOVE SERVE ONE ANOTHER', 'How freedom expresses itself among believers.', 'Galatians 5:13 — by love serve one another', 'Galatians 5:13', 'love serve one another. 14 For all the law is fulfilled in one word, even in this; Thou shalt love thy neighbour as thyself. 15 But if ye bite and devour one another, take heed that ye be not consumed one of another. 16 This I say then, Wal', 'True liberty kneels to serve.', 4),
  ('ephesians-unity-1', 'ephesians-unity', 'ONE LORD ONE FAITH ONE BAPTISM', 'Threefold unity in Paul’s list for the church.', 'Ephesians 4:5 — One Lord, one faith, one baptism', 'Ephesians 4:5', 'One Lord, one faith, one baptism, 6 One God and Father of all, who is above all, and through all, and in you all. 7 But unto every one of us is given grace according to the measure of the gift of Christ. 8 Wherefore he saith, When he ascended', 'Unity is grounded in Christ, not in compromise of truth.', 0),
  ('ephesians-unity-2', 'ephesians-unity', 'ENDEAVOURING TO KEEP THE UNITY', 'How believers preserve the Spirit’s unity.', 'Ephesians 4:3 — Endeavouring to keep the unity of the Spirit in the bond of ', 'Ephesians 4:3', 'Endeavouring to keep the unity of the Spirit in the bond of peace. 4 There is one body, and one Spirit, even as ye are called in one hope of your calling; 5 One Lord, one faith, one baptism, 6 One God and Father of all, who is above all, and t', 'Unity is kept by effort under the Spirit’s bond.', 1),
  ('ephesians-unity-3', 'ephesians-unity', 'SPEAKING THE TRUTH IN LOVE', 'How the body grows up into Christ the head.', 'Ephesians 4:15 — speaking the truth in love', 'Ephesians 4:15', 'Speaking the truth in love, may grow up into him in all things, which is the head, even Christ: 16 From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the me', 'Last-day messages need both truth and love.', 2),
  ('ephesians-unity-4', 'ephesians-unity', 'GROW UP INTO HIM IN ALL THINGS', 'Goal of church maturity under Christ the head.', 'Ephesians 4:15 — may grow up into him in all things, which is the head, even ', 'Ephesians 4:15', 'grow up into him in all things, which is the head, even Christ: 16 From whom the whole body fitly joined together and compacted by that which every joint supplieth, according to the effectual working in the measure of every part, maketh', 'Maturity is measured by likeness to Christ.', 3),
  ('ephesians-unity-5', 'ephesians-unity', 'WE ARE HIS WORKMANSHIP', 'Created in Christ Jesus unto good works.', 'Ephesians 2:10 — we are his workmanship, created in Christ Jesus unto good wo', 'Ephesians 2:10', 'For we are his workmanship, created in Christ Jesus unto good works, which God hath before ordained that we should walk in them. 11 Wherefore remember, that ye being in time past Gentiles in the flesh, who are called Uncircumcision by that which', 'Grace produces works; works never purchase grace.', 4),
  ('philippians-mind-1', 'philippians-mind', 'LET THIS MIND BE IN YOU', 'Paul’s call to share the attitude of Christ Jesus.', 'Philippians 2:5 — Let this mind be in you, which was also in Christ Jesus', 'Philippians 2:5', 'Let this mind be in you, which was also in Christ Jesus: 6 Who, being in the form of God, thought it not robbery to be equal with God: 7 But made himself of no reputation, and took upon him the form of a servant, and was made in the likeness', 'The last generation needs the humility of the cross.', 0),
  ('philippians-mind-2', 'philippians-mind', 'HE HUMBLED HIMSELF', 'Christ’s descent even to the death of the cross.', 'Philippians 2:8 — he humbled himself, and became obedient unto death', 'Philippians 2:8', 'humbled himself, and became obedient unto death, even the death of the cross. 9 Wherefore God also hath highly exalted him, and given him a name which is above every name: 10 That at the name of Jesus every knee should bow, of things in he', 'Obedience unto death is the path of the Lamb.', 1),
  ('philippians-mind-3', 'philippians-mind', 'GOD ALSO HATH HIGHLY EXALTED HIM', 'Father’s response to the Son’s humiliation.', 'Philippians 2:9 — God also hath highly exalted him', 'Philippians 2:9', 'Wherefore God also hath highly exalted him, and given him a name which is above every name: 10 That at the name of Jesus every knee should bow, of things in heaven, and things in earth, and things under the earth; 11 And that every tongue should confes', 'The cross precedes the crown for Christ and His people.', 2),
  ('philippians-mind-4', 'philippians-mind', 'I PRESS TOWARD THE MARK', 'Paul’s pursuit of the prize of the high calling.', 'Philippians 3:14 — I press toward the mark for the prize of the high calling of', 'Philippians 3:14', 'I press toward the mark for the prize of the high calling of God in Christ Jesus. 15 Let us therefore, as many as be perfect, be thus minded: and if in any thing ye be otherwise minded, God shall reveal even this unto you. 16 Nevertheless, wh', 'Sanctification is forward motion, not past achievement.', 3),
  ('philippians-mind-5', 'philippians-mind', 'MY GOD SHALL SUPPLY ALL YOUR NEED', 'Promise through Christ Jesus according to His riches.', 'Philippians 4:19 — my God shall supply all your need according to his riches in', 'Philippians 4:19', 'But my God shall supply all your need according to his riches in glory by Christ Jesus. 20 Now unto God and our Father be glory for ever and ever. Amen. 21 Salute every saint in Christ Jesus. The brethren which are with me greet you. 22 All the sa', 'Provision for mission comes from heaven’s treasury.', 4),
  ('colossians-christ-1', 'colossians-christ', 'BY HIM WERE ALL THINGS CREATED', 'Christ’s role in making heaven and earth.', 'Colossians 1:16 — by him were all things created', 'Colossians 1:16', 'him were all things created, that are in heaven, and that are in earth, visible and invisible, whether they be thrones, or dominions, or principalities, or powers: all things were created by him, and for him: 17 And he is before all thing', 'Creator Christ is worthy of the first angel’s worship call.', 0),
  ('colossians-christ-2', 'colossians-christ', 'HE IS BEFORE ALL THINGS', 'Christ’s preeminence over creation.', 'Colossians 1:17 — he is before all things, and by him all things consist', 'Colossians 1:17', 'is before all things, and by him all things consist. 18 And he is the head of the body, the church: who is the beginning, the firstborn from the dead; that in all things he might have the preeminence. 19 For it pleased the Father that in h', 'History holds together only in Christ.', 1),
  ('colossians-christ-3', 'colossians-christ', 'IN HIM DWELLETH ALL THE FULNESS', 'Fullness of the Godhead bodily in Christ.', 'Colossians 2:9 — in him dwelleth all the fulness of the Godhead bodily', 'Colossians 2:9', 'For in him dwelleth all the fulness of the Godhead bodily. 10 And ye are complete in him, which is the head of all principality and power: 11 In whom also ye are circumcised with the circumcision made without hands, in putting off the body of the', 'We need no lesser mediator than the fullness of God in Christ.', 2),
  ('colossians-christ-4', 'colossians-christ', 'YE ARE COMPLETE IN HIM', 'Status of believers who are in the head of all principality.', 'Colossians 2:10 — ye are complete in him', 'Colossians 2:10', 'And ye are complete in him, which is the head of all principality and power: 11 In whom also ye are circumcised with the circumcision made without hands, in putting off the body of the sins of the flesh by the circumcision of Christ: 12 Buried wi', 'Completeness is in Christ, not in human additions to the gospel.', 3),
  ('colossians-christ-5', 'colossians-christ', 'YOUR LIFE IS HID WITH CHRIST IN GOD', 'Security of the risen life kept safe in heaven.', 'Colossians 3:3 — your life is hid with Christ in God', 'Colossians 3:3', 'For ye are dead, and your life is hid with Christ in God. 4 When Christ, who is our life, shall appear, then shall ye also appear with him in glory. 5 Mortify therefore your members which are upon the earth; fornication, uncleanness, inordinate affection, evil co', 'When Christ appears, the hidden life will be revealed in glory.', 4),
  ('thessalonians-hope-1', 'thessalonians-hope', 'THE LORD HIMSELF SHALL DESCEND', 'Personal descent of the Lord from heaven with a shout.', '1 Thessalonians 4:16 — the Lord himself shall descend from heaven with a shout', '1 Thessalonians 4:16', 'For the Lord himself shall descend from heaven with a shout, with the voice of the archangel, and with the trump of God: and the dead in Christ shall rise first: 17 Then we which are alive and remain shall be caught up together with them in the', 'The Advent is personal — the Lord Himself comes.', 0),
  ('thessalonians-hope-2', 'thessalonians-hope', 'THE DEAD IN CHRIST SHALL RISE FIRST', 'Order of events at the trumpet of God.', '1 Thessalonians 4:16 — the dead in Christ shall rise first', '1 Thessalonians 4:16', 'dead in Christ shall rise first: 17 Then we which are alive and remain shall be caught up together with them in the clouds, to meet the Lord in the air: and so shall we ever be with the Lord. 18 Wherefore comfort one another with these wo', 'Graves cannot hold those who sleep in Jesus.', 1),
  ('thessalonians-hope-3', 'thessalonians-hope', 'CAUGHT UP TOGETHER WITH THEM', 'Living saints join the raised ones in the clouds.', '1 Thessalonians 4:17 — caught up together with them in the clouds', '1 Thessalonians 4:17', 'Caught up together with them in the clouds, to meet the Lord in the air: and so shall we ever be with the Lord. 18 Wherefore comfort one another with these words. 1 Thessalonians 4 2606 1 Thessalonians 4', 'Family reunion in the air with the Lord forever.', 2),
  ('thessalonians-hope-4', 'thessalonians-hope', 'SO SHALL WE EVER BE WITH THE LORD', 'Eternal outcome after the catching up.', '1 Thessalonians 4:17 — so shall we ever be with the Lord', '1 Thessalonians 4:17', 'shall we ever be with the Lord. 18 Wherefore comfort one another with these words. 1 Thessalonians 4 2606 1 Thessalonians 4', 'Heaven’s joy is perpetual presence with Christ.', 3),
  ('thessalonians-hope-5', 'thessalonians-hope', 'TO MEET THE LORD IN THE AIR', 'Where living saints join the raised ones when Christ descends.', '1 Thessalonians 4:17 — to meet the Lord in the air', '1 Thessalonians 4:17', 'meet the Lord in the air: and so shall we ever be with the Lord. 18 Wherefore comfort one another with these words. 1 Thessalonians 4 2606 1 Thessalonians 4', 'Prophecy is for comfort as well as warning — reunion in the air with Christ forever.', 4),
  ('timothy-scripture-1', 'timothy-scripture', 'ALL SCRIPTURE IS GIVEN BY INSPIRATION', 'Paul’s doctrine of how Scripture comes from God.', '2 Timothy 3:16 — All scripture is given by inspiration of God', '2 Timothy 3:16', 'All scripture is given by inspiration of God, and is profitable for doctrine, for reproof, for correction, for instruction in righteousness: 17 That the man of God may be perfect, throughly furnished unto all good works. 2 Timothy 3 2626 2 T', 'Last-day faith rests on God-breathed Scripture.', 0),
  ('timothy-scripture-2', 'timothy-scripture', 'PROFITABLE FOR DOCTRINE', 'First use Paul lists for inspired Scripture.', '2 Timothy 3:16 — profitable for doctrine, for reproof, for correction', '2 Timothy 3:16', 'All scripture is given by inspiration of God, and is profitable for doctrine, for reproof, for correction, for instruction in righteousness: 17 That the man of God may be perfect, throughly furnished unto all good works. 2 Timothy 3 2626 2 Timothy 3', 'Doctrine must be Bible-derived, not tradition-driven.', 1),
  ('timothy-scripture-3', 'timothy-scripture', 'THAT THE MAN OF GOD MAY BE PERFECT', 'Purpose of Scripture’s thorough equipment.', '2 Timothy 3:17 — That the man of God may be perfect, throughly furnished', '2 Timothy 3:17', 'That the man of God may be perfect, throughly furnished unto all good works. 2 Timothy 3 2626 2 Timothy 3', 'Scripture completes the worker for every good work.', 2),
  ('timothy-scripture-4', 'timothy-scripture', 'PREACH THE WORD', 'Paul’s solemn charge to Timothy before God and Christ.', '2 Timothy 4:2 — Preach the word; be instant in season, out of season', '2 Timothy 4:2', 'Preach the word; be instant in season, out of season; reprove, rebuke, exhort with all longsuffering and doctrine. 3 For the time will come when they will not endure sound doctrine; but after their own lusts shall they heap to themselves tea', 'The loud cry is still the preached Word.', 3),
  ('timothy-scripture-5', 'timothy-scripture', 'THEY WILL NOT ENDURE SOUND DOCTRINE', 'End-time itching ears that heap teachers to themselves.', '2 Timothy 4:3 — they will not endure sound doctrine', '2 Timothy 4:3', 'For the time will come when they will not endure sound doctrine; but after their own lusts shall they heap to themselves teachers, having itching ears; 4 And they shall turn away their ears from the truth, and shall be turned unto fables. 5 But watch thou in all things,', 'Popularity is no test of truth in the last days.', 4),
  ('hebrews-faith-1', 'hebrews-faith', 'FAITH IS THE SUBSTANCE OF THINGS HOPED FOR', 'Hebrews’ definition of faith.', 'Hebrews 11:1 — faith is the substance of things hoped for', 'Hebrews 11:1', 'Now faith is the substance of things hoped for, the evidence of things not seen. 2 For by it the elders obtained a good report. 3 Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not m', 'Faith treats God’s promises as present reality.', 0),
  ('hebrews-faith-2', 'hebrews-faith', 'THE EVIDENCE OF THINGS NOT SEEN', 'Second half of faith’s definition.', 'Hebrews 11:1 — the evidence of things not seen', 'Hebrews 11:1', 'Now faith is the substance of things hoped for, the evidence of things not seen. 2 For by it the elders obtained a good report. 3 Through faith we understand that the worlds were framed by the word of God, so that things which are seen were not made of things which do appear. 4 By faith Abe', 'Sight will confirm what faith already holds.', 1),
  ('hebrews-faith-3', 'hebrews-faith', 'WITHOUT FAITH IT IS IMPOSSIBLE TO PLEASE HIM', 'Necessity of faith for anyone who comes to God.', 'Hebrews 11:6 — without faith it is impossible to please him', 'Hebrews 11:6', 'But without faith it is impossible to please him: for he that cometh to God must believe that he is, and that he is a rewarder of them that diligently seek him. 7 By faith Noah, being warned of God of things not seen as yet, moved with fear, pre', 'The remnant walks by faith when miracles multiply on both sides.', 2),
  ('hebrews-faith-4', 'hebrews-faith', 'LOOKING UNTO JESUS', 'Author and finisher of our faith.', 'Hebrews 12:2 — Looking unto Jesus the author and finisher of our faith', 'Hebrews 12:2', 'Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the throne of God. 3 For consider him that endured such contradicti', 'Eyes on Jesus finish the race begun by grace.', 3),
  ('hebrews-faith-5', 'hebrews-faith', 'LET US RUN WITH PATIENCE', 'The race set before us, laid aside every weight.', 'Hebrews 12:1 — let us run with patience the race that is set before us', 'Hebrews 12:1', 'us run with patience the race that is set before us, 2 Looking unto Jesus the author and finisher of our faith; who for the joy that was set before him endured the cross, despising the shame, and is set down at the right hand of the thro', 'Patience is the endurance of the saints in Revelation too.', 4),
  ('james-works-1', 'james-works', 'BE YE DOERS OF THE WORD', 'James’ appeal not to be hearers only.', 'James 1:22 — be ye doers of the word, and not hearers only', 'James 1:22', 'But be ye doers of the word, and not hearers only, deceiving your own selves. 23 For if any be a hearer of the word, and not a doer, he is like unto a man beholding his natural face in a glass: James 1 2658 James 1', 'Knowledge without obedience deceives the soul.', 0),
  ('james-works-2', 'james-works', 'FAITH WITHOUT WORKS IS DEAD', 'James’ verdict on claim-only religion.', 'James 2:26 — faith without works is dead also', 'James 2:26', 'without works is dead also. 2661 James 2', 'Living faith acts; empty profession does not save.', 1),
  ('james-works-3', 'james-works', 'PURE RELIGION AND UNDEFILED', 'Visiting orphans and widows; keeping unspotted from the world.', 'James 1:27 — Pure religion and undefiled before God and the Father is thi', 'James 1:27', 'Pure religion and undefiled before God and the Father is this, To visit the fatherless and widows in their affliction, and to keep himself unspotted from the world. 2659 James 1', 'True piety serves the vulnerable and stays unspotted.', 2),
  ('james-works-4', 'james-works', 'RESIST THE DEVIL', 'James’ command so that the devil will flee.', 'James 4:7 — Resist the devil, and he will flee from you', 'James 4:7', 'Resist the devil, and he will flee from you. 8 Draw nigh to God, and he will draw nigh to you. Cleanse your hands, ye sinners; and purify your hearts, ye double minded. 9 Be afflicted, and mourn, and weep: let your laughter be turned to mourn', 'Resistance under God’s submission ends Satan’s bluff.', 3),
  ('james-works-5', 'james-works', 'DRAW NIGH TO GOD', 'James promises reciprocal nearness when you approach the throne.', 'James 4:8 — Draw nigh to God, and he will draw nigh to you', 'James 4:8', 'Draw nigh to God, and he will draw nigh to you. Cleanse your hands, ye sinners; and purify your hearts, ye double minded. 9 Be afflicted, and mourn, and weep: let your laughter be turned to mourning, and your joy to heaviness. 10 Humble yours', 'Nearness to God is the safeguard of the last days.', 4),
  ('peter-promise-1', 'peter-promise', 'EXCEEDING GREAT AND PRECIOUS PROMISES', 'Given that we might be partakers of the divine nature.', '2 Peter 1:4 — exceeding great and precious promises', '2 Peter 1:4', 'Exceeding great and precious promises: that by these ye might be partakers of the divine nature, having escaped the corruption that is in the world through lust. 5 And beside this, giving all diligence, add to your faith virtue; and to virtu', 'Promises are the ladder of character growth.', 0),
  ('peter-promise-2', 'peter-promise', 'PARTAKERS OF THE DIVINE NATURE', 'Result of claiming God’s promises by faith.', '2 Peter 1:4 — partakers of the divine nature', '2 Peter 1:4', 'Partakers of the divine nature, having escaped the corruption that is in the world through lust. 5 And beside this, giving all diligence, add to your faith virtue; and to virtue knowledge; 6 And to knowledge temperance; and to temperance pati', 'Sanctification is sharing God’s life, not mere self-improvement.', 1),
  ('peter-promise-3', 'peter-promise', 'A MORE SURE WORD OF PROPHECY', 'Peter’s confidence even above the mount of transfiguration vision.', '2 Peter 1:19 — We have also a more sure word of prophecy', '2 Peter 1:19', 'We have also a more sure word of prophecy; whereunto ye do well that ye take heed, as unto a light that shineth in a dark place, until the day dawn, and the day star arise in your hearts: 20 Knowing this first, that no prophecy of the script', 'Prophetic Scripture outranks private experience.', 2),
  ('peter-promise-4', 'peter-promise', 'AS UNTO A LIGHT THAT SHINETH', 'How prophecy functions in a dark place.', '2 Peter 1:19 — as unto a light that shineth in a dark place', '2 Peter 1:19', 'unto a light that shineth in a dark place, until the day dawn, and the day star arise in your hearts: 20 Knowing this first, that no prophecy of the scripture is of any private interpretation. 21 For the prophecy came not in old time by th', 'Prophecy lights the path until the day dawn.', 3),
  ('peter-promise-5', 'peter-promise', 'NO PROPHECY OF THE SCRIPTURE IS OF ANY PRIVATE INTERPRETATION', 'Peter’s rule for handling prophetic Scripture.', '2 Peter 1:20 — no prophecy of the scripture is of any private interpretatio', '2 Peter 1:20', 'prophecy of the scripture is of any private interpretation. 21 For the prophecy came not in old time by the will of man: but holy men of God spake as they were moved by the Holy Ghost. 2676 2 Peter 1', 'Humble, Spirit-led interpretation guards against speculation.', 4),
  ('john-love-1', 'john-love', 'GOD IS LOVE', 'John’s simple revelation of God’s essential nature.', '1 John 4:8 — for God is love', '1 John 4:8', 'He that loveth not knoweth not God; for God is love. 9 In this was manifested the love of God toward us, because that God sent his only begotten Son into the world, that we might live through him. 10 Herein is love, not that we loved God, but that he loved us, and sent his Son', 'Every last-day doctrine must be read in the light of God’s love.', 0),
  ('john-love-2', 'john-love', 'WE LOVE HIM BECAUSE HE FIRST LOVED US', 'Source of Christian love.', '1 John 4:19 — We love him, because he first loved us', '1 John 4:19', 'We love him, because he first loved us. 20 If a man say, I love God, and hateth his brother, he is a liar: for he that loveth not his brother whom he hath seen, how can he love God whom he hath not seen? 21 And this commandment have we from h', 'Obedience is response to love already given.', 1),
  ('john-love-3', 'john-love', 'THIS IS THE LOVE OF GOD', 'That we keep His commandments.', '1 John 5:3 — this is the love of God, that we keep his commandments', '1 John 5:3', 'For this is the love of God, that we keep his commandments: and his commandments are not grievous. 4 For whatsoever is born of God overcometh the world: and this is the victory that overcometh the world, even our faith. 5 Who is he that overcomet', 'Love and law are not enemies in Scripture.', 2),
  ('john-love-4', 'john-love', 'HIS COMMANDMENTS ARE NOT GRIEVOUS', 'John’s testimony about the weight of God’s commands.', '1 John 5:3 — his commandments are not grievous', '1 John 5:3', 'For this is the love of God, that we keep his commandments: and his commandments are not grievous. 4 For whatsoever is born of God overcometh the world: and this is the victory that overcometh the world, even our faith. 5 Who is he that overcometh the world, but he that believeth that Jesus is the Son of', 'Grace makes the yoke easy and the burden light.', 3),
  ('john-love-5', 'john-love', 'HE THAT HATH THE SON HATH LIFE', 'Eternal life defined by possession of the Son.', '1 John 5:12 — He that hath the Son hath life', '1 John 5:12', 'He that hath the Son hath life; and he that hath not the Son of God hath not life. 13 These things have I written unto you that believe on the name of the Son of God; that ye may know that ye have eternal life, and that ye may believe on the', 'Life is a Person before it is a place.', 4),
  ('jude-contend-1', 'jude-contend', 'EARNESTLY CONTEND FOR THE FAITH', 'Jude’s appeal for the faith once delivered unto the saints.', 'Jude 1:3 — earnestly contend for the faith which was once delivered unt', 'Jude 1:3', 'Earnestly contend for the faith which was once delivered unto the saints. 4 For there are certain men crept in unawares, who were before of old ordained to this condemnation, ungodly men, turning the grace of our God into lasciviousness, and', 'Truth is worth earnest, loving contention.', 0),
  ('jude-contend-2', 'jude-contend', 'ONCE DELIVERED UNTO THE SAINTS', 'The faith is not a modern invention.', 'Jude 1:3 — the faith which was once delivered unto the saints', 'Jude 1:3', 'faith which was once delivered unto the saints. 4 For there are certain men crept in unawares, who were before of old ordained to this condemnation, ungodly men, turning the grace of our God into lasciviousness, and denying the only Lord', 'Apostolic faith is the standard for the end-time church.', 1),
  ('jude-contend-3', 'jude-contend', 'BUILDING UP YOURSELVES ON YOUR MOST HOLY FAITH', 'How to keep in the love of God while contending.', 'Jude 1:20 — building up yourselves on your most holy faith', 'Jude 1:20', 'But ye, beloved, building up yourselves on your most holy faith, praying in the Holy Ghost, 21 Keep yourselves in the love of God, looking for the mercy of our Lord Jesus Christ unto eternal life. 22 And of some have compassion, making a difference: 23 And oth', 'Defense of truth requires personal spiritual construction.', 2),
  ('jude-contend-4', 'jude-contend', 'PRAYING IN THE HOLY GHOST', 'Jude’s companion to building on holy faith.', 'Jude 1:20 — praying in the Holy Ghost', 'Jude 1:20', 'But ye, beloved, building up yourselves on your most holy faith, praying in the Holy Ghost, 21 Keep yourselves in the love of God, looking for the mercy of our Lord Jesus Christ unto eternal life. 22 And of some have compassion, making a difference: 23 And others save with fear, pulling them out of the fire', 'Prayer in the Spirit fuels faithful contention.', 3),
  ('jude-contend-5', 'jude-contend', 'KEEP YOURSELVES IN THE LOVE OF GOD', 'Looking for the mercy of our Lord Jesus Christ unto eternal life.', 'Jude 1:21 — Keep yourselves in the love of God', 'Jude 1:21', 'Keep yourselves in the love of God, looking for the mercy of our Lord Jesus Christ unto eternal life. 22 And of some have compassion, making a difference: 23 And others save with fear, pulling them out of the fire; hating even the garment spo', 'Stay in love while you stand for truth.', 4),
  ('rev-letters-1', 'rev-letters', 'I KNOW THY WORKS', 'Christ’s repeated knowledge of each church’s condition.', 'Revelation 2:2 — I know thy works', 'Revelation 2:2', 'I know thy works, and thy labour, and thy patience, and how thou canst not bear them which are evil: and thou hast tried them which say they are apostles, and are not, and hast found them liars: 3 And hast borne, and hast patience, and for m', 'Nothing about the church is hidden from its Head.', 0),
  ('rev-letters-2', 'rev-letters', 'BE THOU FAITHFUL UNTO DEATH', 'Promise of a crown of life to Smyrna’s sufferers.', 'Revelation 2:10 — be thou faithful unto death, and I will give thee a crown of', 'Revelation 2:10', 'thou faithful unto death, and I will give thee a crown of life. 11 He that hath an ear, let him hear what the Spirit saith unto the churches; He that overcometh shall not be hurt of the second death. 12 And to the angel of the church in Pe', 'Faithfulness, not length of life, wins the crown.', 1),
  ('rev-letters-3', 'rev-letters', 'HOLD THAT FAST WHICH THOU HAST', 'Counsel so that no man take thy crown.', 'Revelation 3:11 — hold that fast which thou hast, that no man take thy crown', 'Revelation 3:11', 'Behold, I come quickly: hold that fast which thou hast, that no man take thy crown. 12 Him that overcometh will I make a pillar in the temple of my God, and he shall go no more out: and I will write upon him the name of my God, and the name of the city of my God, w', 'Preserve present truth until Jesus comes.', 2),
  ('rev-letters-4', 'rev-letters', 'I STAND AT THE DOOR AND KNOCK', 'Christ’s appeal outside Laodicea’s door.', 'Revelation 3:20 — Behold, I stand at the door, and knock', 'Revelation 3:20', 'Behold, I stand at the door, and knock: if any man hear my voice, and open the door, I will come in to him, and will sup with him, and he with me. 21 To him that overcometh will I grant to sit with me in my throne, even as I also overcame, a', 'Even lukewarm hearts hear a personal knock of mercy.', 3),
  ('rev-letters-5', 'rev-letters', 'TO HIM THAT OVERCOMETH', 'Repeated promise formula in the seven letters.', 'Revelation 3:21 — To him that overcometh will I grant to sit with me in my thr', 'Revelation 3:21', 'To him that overcometh will I grant to sit with me in my throne, even as I also overcame, and am set down with my Father in his throne. 22 He that hath an ear, let him hear what the Spirit saith unto the churches. 2703 Revelation 3', 'Overcoming is possible in Christ for every church age.', 4),
  ('rev-final-1', 'rev-final', 'BLESSED IS HE THAT READETH', 'Opening beatitude of Revelation for readers and keepers.', 'Revelation 1:3 — Blessed is he that readeth, and they that hear the words of ', 'Revelation 1:3', 'Blessed is he that readeth, and they that hear the words of this prophecy, and keep those things which are written therein: for the time is at hand. 4 John to the seven churches which are in Asia: Grace be unto you, and peace, from him which', 'Prophetic study is commanded and blessed.', 0),
  ('rev-final-2', 'rev-final', 'KEEP THOSE THINGS WHICH ARE WRITTEN', 'Blessing tied to keeping Revelation’s words.', 'Revelation 1:3 — keep those things which are written therein', 'Revelation 1:3', 'those things which are written therein: for the time is at hand. 4 John to the seven churches which are in Asia: Grace be unto you, and peace, from him which is, and which was, and which is to come; and from the seven Spirits which are', 'Hearing without keeping forfeits the blessing.', 1),
  ('rev-final-3', 'rev-final', 'THE TIME IS AT HAND', 'Urgency attached to Revelation’s opening blessing.', 'Revelation 1:3 — for the time is at hand', 'Revelation 1:3', 'the time is at hand. 4 John to the seven churches which are in Asia: Grace be unto you, and peace, from him which is, and which was, and which is to come; and from the seven Spirits which are before his throne; 5 And from Jesus Christ, wh', 'Urgency is part of the book’s message in every age.', 2),
  ('rev-final-4', 'rev-final', 'SURELY I COME QUICKLY', 'Jesus’ thrice-echoed closing promise.', 'Revelation 22:20 — Surely I come quickly', 'Revelation 22:20', 'He which testifieth these things saith, Surely I come quickly. Amen. Even so, come, Lord Jesus. 21 The grace of our Lord Jesus Christ be with you all. Amen. 2734 Revelation 22', 'The last word of Jesus in Scripture is soon return.', 3),
  ('rev-final-5', 'rev-final', 'EVEN SO COME LORD JESUS', 'John’s response to the promise of soon coming.', 'Revelation 22:20 — Even so, come, Lord Jesus', 'Revelation 22:20', 'Even so, come, Lord Jesus. 21 The grace of our Lord Jesus Christ be with you all. Amen. 2734 Revelation 22', 'The remnant’s prayer matches heaven’s promise.', 4),
  ('psalms-refuge-1', 'psalms-refuge', 'THE LORD IS MY SHEPHERD', 'Opening of the best-known psalm of trust.', 'Psalm 23:1 — The LORD is my shepherd; I shall not want', 'Psalm 23:1', 'The Lord is my shepherd; I shall not want. 2 He maketh me to lie down in green pastures: he leadeth me beside the still waters. 3 He restoreth my soul: he leadeth me in the paths of righteousness for his name''s sake. 4 Yea, though I walk throu', 'Shepherd care continues through the valley of the shadow.', 0),
  ('psalms-refuge-2', 'psalms-refuge', 'HE LEADETH ME BESIDE THE STILL WATERS', 'Restoring path of the Shepherd for the soul.', 'Psalm 23:2 — he leadeth me beside the still waters', 'Psalm 23:2', 'He maketh me to lie down in green pastures: he leadeth me beside the still waters. 3 He restoreth my soul: he leadeth me in the paths of righteousness for his name''s sake. 4 Yea, though I walk through the valley of the shadow of death, I will fear no evil: for thou art with me; thy rod', 'God’s leading is restful even in crisis seasons.', 1),
  ('psalms-refuge-3', 'psalms-refuge', 'THY WORD IS A LAMP UNTO MY FEET', 'How Scripture guides step by step.', 'Psalm 119:105 — Thy word is a lamp unto my feet, and a light unto my path', 'Psalm 119:105', 'Thy word is a lamp unto my feet, and a light unto my path. 106 I have sworn, and I will perform it, that I will keep thy righteous judgments. 107 I am afflicted very much: quicken me, O Lord, according unto thy word. 108 Accept, I beseech thee', 'Path light for the last days is still the Word.', 2),
  ('psalms-refuge-4', 'psalms-refuge', 'GOD IS OUR REFUGE AND STRENGTH', 'A very present help in trouble.', 'Psalm 46:1 — God is our refuge and strength, a very present help in troub', 'Psalm 46:1', 'God is our refuge and strength, a very present help in trouble. 2 Therefore will not we fear, though the earth be removed, and though the mountains be carried into the midst of the sea; 3 Though the waters thereof roar and be troubled, though', 'Refuge is a Person when the earth is removed.', 3),
  ('psalms-refuge-5', 'psalms-refuge', 'BE STILL AND KNOW THAT I AM GOD', 'Command in the psalm of God’s exaltation among the nations.', 'Psalm 46:10 — Be still, and know that I am God', 'Psalm 46:10', 'Be still, and know that I am God: I will be exalted among the heathen, I will be exalted in the earth. 11 The Lord of hosts is with us; the God of Jacob is our refuge. Selah. Psalm 46 1105 Psalm 46', 'Stillness before God steadies the end-time heart.', 4),
  ('proverbs-wisdom-1', 'proverbs-wisdom', 'THE FEAR OF THE LORD IS THE BEGINNING OF WISDOM', 'Foundation of true knowledge.', 'Proverbs 9:10 — The fear of the LORD is the beginning of wisdom', 'Proverbs 9:10', 'The fear of the Lord is the beginning of wisdom: a good understanding have all they that do his commandments: his praise endureth for ever. Psalm 111 1184 Psalm 111', 'Reverence for God is the first lesson of true education.', 0),
  ('proverbs-wisdom-2', 'proverbs-wisdom', 'TRUST IN THE LORD WITH ALL THINE HEART', 'Call not to lean on your own understanding.', 'Proverbs 3:5 — Trust in the LORD with all thine heart', 'Proverbs 3:5', 'Trust in the Lord with all thine heart; and lean not unto thine own understanding. 6 In all thy ways acknowledge him, and he shall direct thy paths. 7 Be not wise in thine own eyes: fear the Lord, and depart from evil. 8 It shall be health to', 'Whole-heart trust is the remnant’s security system.', 1),
  ('proverbs-wisdom-3', 'proverbs-wisdom', 'LEAN NOT UNTO THINE OWN UNDERSTANDING', 'Companion command to whole-heart trust.', 'Proverbs 3:5 — lean not unto thine own understanding', 'Proverbs 3:5', 'Trust in the Lord with all thine heart; and lean not unto thine own understanding. 6 In all thy ways acknowledge him, and he shall direct thy paths. 7 Be not wise in thine own eyes: fear the Lord, and depart from evil. 8 It shall be health to thy navel, and marrow to thy bones. 9 Honour', 'Self-wisdom fails in the final crisis.', 2),
